function getSafeRecordset(result) {
    if (Array.isArray(result?.recordset)) return result.recordset.map(normalizeDbRowDateValues);
    if (Array.isArray(result?.recordsets?.[0])) return result.recordsets[0].map(normalizeDbRowDateValues);
    return [];
}

function cloneDbRow(row) {
    return normalizeDbRowDateValues(row || {});
}

async function executeQuery(pool, query, inputs = {}) {
    if (!query || typeof query !== "string" || !query.trim()) {
        console.warn("[executeQuery] Empty or invalid SQL query skipped.");
        return [];
    }

    const request = pool.request();

    Object.keys(inputs || {}).forEach(key => {
        const input = inputs[key];
        if (!input || !input.type) return;

        request.input(
            key,
            input.type,
            input.value
        );
    });

    const result = await request.query(query);
    return getSafeRecordset(result).map(cloneDbRow);
}

async function tableExists(pool, tableName) {
    const result = await pool.request()
        .input("tableName", sql.NVarChar, tableName)
        .query(`
            SELECT 1 AS existsFlag
            FROM INFORMATION_SCHEMA.TABLES
            WHERE TABLE_NAME = @tableName
        `);

    return result.recordset.length > 0;
}

async function tableColumnExists(pool, tableName, columnName) {
    const result = await pool.request()
        .input("tableName", sql.NVarChar, tableName)
        .input("columnName", sql.NVarChar, columnName)
        .query(`
            SELECT 1 AS existsFlag
            FROM INFORMATION_SCHEMA.COLUMNS
            WHERE TABLE_NAME = @tableName
              AND COLUMN_NAME = @columnName
        `);

    return result.recordset.length > 0;
}

async function hasBiosInventoryTables(pool) {
    try {
        const [hasCurrent, hasValue] = await Promise.all([
            tableExists(pool, "TSHI_OBJECT_CURRENT"),
            tableExists(pool, "TSHI_OBJECT_VALUE")
        ]);

        return hasCurrent && hasValue;
    } catch (err) {
        console.warn("BIOS inventory table check skipped:", err.message);
        return false;
    }
}

function getBiosSqlFragments(rootAlias = "a", connectionAlias = rootAlias, includeBios = false) {
    if (!includeBios) {
        return {
            select: `CAST(NULL AS NVARCHAR(100)) AS BiosDate,
        CAST(NULL AS INT) AS PCAge`,
            join: ""
        };
    }

    const parsedBiosDate = `COALESCE(
            TRY_CONVERT(date, biosValue.Object_Value_Str, 120),
            TRY_CONVERT(date, biosValue.Object_Value_Str, 103),
            TRY_CONVERT(date, biosValue.Object_Value_Str, 101),
            TRY_CONVERT(date, biosValue.Object_Value_Str)
        )`;

    return {
        select: `biosValue.Object_Value_Str AS BiosDate,
        CASE
            WHEN ${parsedBiosDate} IS NULL THEN NULL
            ELSE DATEDIFF(YEAR, ${parsedBiosDate}, ISNULL(${connectionAlias}.ConnectionTime, GETDATE()))
        END AS PCAge`,
        join: `
        LEFT JOIN TSHI_OBJECT_CURRENT biosCurrent WITH (NOLOCK)
            ON ${rootAlias}.Object_Root_Idn = biosCurrent.Object_Root_Idn
           AND biosCurrent.Object_Field_Idn = 14
        LEFT JOIN TSHI_OBJECT_VALUE biosValue WITH (NOLOCK)
            ON biosValue.Object_Value_Idn = biosCurrent.Object_Value_Idn`
    };
}

async function getDepartmentsRecursive(pool, parentID){
    let query = `
SELECT DISTINCT
    a.Object_Rel_Idn
    ,a.Object_Rel_Name
    ,a.Object_Full_Name
    ,a.Object_PR_Idn
FROM TS_OBJECT_RELATION a
WHERE a.Object_PR_Idn = @parentID
    AND a.Object_Rel_Deleted = 0;
        `;

    const result = await pool.request()
        .input("parentID", sql.Int, parentID)
        .query(query);

    // RECURSIVELY LOAD CHILD DEPARTMENTS
    const departments = [];

    for (const row of result.recordset) {
        const department = {};

        // DYNAMIC COLUMN MAPPING
        Object.keys(row).forEach(columnName => {
            department[columnName] = row[columnName];
        });

        // LOAD CHILDREN RECURSIVELY
        department['children'] = await getDepartmentsRecursive(pool, row.Object_Rel_Idn);
        departments.push(department);
    }
    return departments;
}

async function getAllHardwareInventoryAssets(pool, options = {}) {
    const limit = Math.max(1, Math.min(parseInt(options.limit, 10) || 10000, 50000));
    const relationID = parseInt(options.relationID, 10) || 0;
    const searchText = normalizeAuthValue(options.search || options.q || "");

    const [hasEmAssets, hasMdmAssets, hasRelation, hasMdmRelation, hasMdmMapping, includeBios] = await Promise.all([
        tableExists(pool, "TS_OBJECT_ROOT"),
        tableExists(pool, "TSMDM_ASSET"),
        tableExists(pool, "TS_OBJECT_RELATION"),
        tableExists(pool, "TSMDM_OBJECT_RELATION"),
        tableExists(pool, "TSMDM_TS_OBJECT_MAPPING"),
        hasBiosInventoryTables(pool)
    ]);

    if (!hasEmAssets && !hasMdmAssets) return [];

    const parts = [];

    if (hasEmAssets) {
        const biosFragments = getBiosSqlFragments("em", "em", includeBios);
        parts.push(`
            SELECT
                em.Object_Root_Idn AS _Idn,
                'EM' AS Object_Agent,
                em.Object_DeviceID,
                em.Object_Root_Idn AS Object_Root_Idn,
                ${hasMdmMapping && hasMdmAssets ? "mdmMap.MDM_Asset_Idn" : "CAST(NULL AS INT)"} AS MDM_Asset_Idn,
                ${hasMdmMapping && hasMdmAssets ? "mdmMap.DeviceID" : "CAST(NULL AS NVARCHAR(255))"} AS MDM_DeviceID,
                ${hasMdmMapping && hasMdmAssets ? "mdmMap.DeviceName" : "CAST(NULL AS NVARCHAR(255))"} AS MDM_DeviceName,
                em.ComputerName,
                ${hasRelation ? "rel.Object_Full_Name" : "CAST(NULL AS NVARCHAR(500))"} AS Object_Full_Name,
                ${hasRelation ? "rel.Object_Rel_Name" : "CAST(NULL AS NVARCHAR(255))"} AS Object_Rel_Name,
                CAST(em.Object_Rel_Idn AS INT) AS Object_Rel_Idn,
                ${hasRelation ? "CAST(rel.Object_PR_Idn AS INT)" : "CAST(NULL AS INT)"} AS Object_PR_Idn,
                'Windows' AS PlatformType,
                em.Model,
                em.ConnectionTime,
                CASE WHEN em.ConnectionStatus = 1 THEN 'Online' ELSE 'Offline' END AS ConnectionStatus,
                em.IP,
                ${biosFragments.select}
            FROM TS_OBJECT_ROOT em WITH (NOLOCK)
            ${hasRelation ? "LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK) ON em.Object_Rel_Idn = rel.Object_Rel_Idn" : ""}
            ${hasMdmMapping && hasMdmAssets ? "LEFT JOIN TSMDM_TS_OBJECT_MAPPING emMap WITH (NOLOCK) ON em.Object_Root_Idn = emMap.Object_Root_Idn" : ""}
            ${hasMdmMapping && hasMdmAssets ? "LEFT JOIN TSMDM_ASSET mdmMap WITH (NOLOCK) ON emMap.MDM_Asset_Idn = mdmMap.MDM_Asset_Idn" : ""}
            ${biosFragments.join}
            WHERE ISNULL(em.Object_Root_Idn, 0) > 0
              AND (@RelationID = 0 OR em.Object_Rel_Idn = @RelationID)
        `);
    }

    if (hasMdmAssets) {
        const mappingExclude = hasMdmMapping
            ? "AND NOT EXISTS (SELECT 1 FROM TSMDM_TS_OBJECT_MAPPING map WITH (NOLOCK) WHERE map.MDM_Asset_Idn = mdm.MDM_Asset_Idn)"
            : "";

        if (relationID > 0 && hasMdmRelation) {
            // Relation-filtered hardware inventory should start from the relation
            // table, not from every MDM asset. This mirrors the fast branch API.
            parts.push(`
                SELECT
                    mdm.MDM_Asset_Idn AS _Idn,
                    'MDM' AS Object_Agent,
                    mdm.DeviceID AS Object_DeviceID,
                    CAST(NULL AS INT) AS Object_Root_Idn,
                    mdm.MDM_Asset_Idn AS MDM_Asset_Idn,
                    mdm.DeviceID AS MDM_DeviceID,
                    mdm.DeviceName AS MDM_DeviceName,
                    mdm.DeviceName AS ComputerName,
                    ${hasRelation ? "rel.Object_Full_Name" : "CAST(NULL AS NVARCHAR(500))"} AS Object_Full_Name,
                    ${hasRelation ? "rel.Object_Rel_Name" : "CAST(NULL AS NVARCHAR(255))"} AS Object_Rel_Name,
                    CAST(mor.Object_Rel_Idn AS INT) AS Object_Rel_Idn,
                    ${hasRelation ? "CAST(rel.Object_PR_Idn AS INT)" : "CAST(NULL AS INT)"} AS Object_PR_Idn,
                    ISNULL(NULLIF(mdm.PlatformType, ''), 'MDM') AS PlatformType,
                    mdm.DeviceModelName AS Model,
                    mdm.DeviceTimeStamp AS ConnectionTime,
                    ISNULL(NULLIF(CAST(mdm.ConnectionStatus AS NVARCHAR(100)), ''), 'Unknown') AS ConnectionStatus,
                    CASE
                        WHEN mdm.DeviceLocalIPAddress IS NULL OR mdm.DeviceLocalIPAddress = '' THEN mdm.DeviceIPAddress
                        ELSE mdm.DeviceLocalIPAddress
                    END AS IP,
                    CAST(NULL AS NVARCHAR(100)) AS BiosDate,
                    CAST(NULL AS INT) AS PCAge
                FROM TSMDM_OBJECT_RELATION mor WITH (NOLOCK)
                INNER JOIN TSMDM_ASSET mdm WITH (NOLOCK)
                    ON mdm.MDM_Asset_Idn = mor.MDM_Asset_Idn
                ${hasRelation ? "LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK) ON mor.Object_Rel_Idn = rel.Object_Rel_Idn" : ""}
                WHERE mor.Object_Rel_Idn = @RelationID
                  ${mappingExclude}
            `);
        } else {
            const mdmRelationJoin = hasMdmRelation
                ? "LEFT JOIN TSMDM_OBJECT_RELATION mor WITH (NOLOCK) ON mdm.MDM_Asset_Idn = mor.MDM_Asset_Idn"
                : "";
            const relationJoin = hasMdmRelation && hasRelation
                ? "LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK) ON mor.Object_Rel_Idn = rel.Object_Rel_Idn"
                : "";
            const relationSelect = hasMdmRelation ? "CAST(mor.Object_Rel_Idn AS INT)" : "CAST(NULL AS INT)";
            parts.push(`
                SELECT
                    mdm.MDM_Asset_Idn AS _Idn,
                    'MDM' AS Object_Agent,
                    mdm.DeviceID AS Object_DeviceID,
                    CAST(NULL AS INT) AS Object_Root_Idn,
                    mdm.MDM_Asset_Idn AS MDM_Asset_Idn,
                    mdm.DeviceID AS MDM_DeviceID,
                    mdm.DeviceName AS MDM_DeviceName,
                    mdm.DeviceName AS ComputerName,
                    ${hasMdmRelation && hasRelation ? "rel.Object_Full_Name" : "CAST(NULL AS NVARCHAR(500))"} AS Object_Full_Name,
                    ${hasMdmRelation && hasRelation ? "rel.Object_Rel_Name" : "CAST(NULL AS NVARCHAR(255))"} AS Object_Rel_Name,
                    ${relationSelect} AS Object_Rel_Idn,
                    ${hasMdmRelation && hasRelation ? "CAST(rel.Object_PR_Idn AS INT)" : "CAST(NULL AS INT)"} AS Object_PR_Idn,
                    ISNULL(NULLIF(mdm.PlatformType, ''), 'MDM') AS PlatformType,
                    mdm.DeviceModelName AS Model,
                    mdm.DeviceTimeStamp AS ConnectionTime,
                    ISNULL(NULLIF(CAST(mdm.ConnectionStatus AS NVARCHAR(100)), ''), 'Unknown') AS ConnectionStatus,
                    CASE
                        WHEN mdm.DeviceLocalIPAddress IS NULL OR mdm.DeviceLocalIPAddress = '' THEN mdm.DeviceIPAddress
                        ELSE mdm.DeviceLocalIPAddress
                    END AS IP,
                    CAST(NULL AS NVARCHAR(100)) AS BiosDate,
                    CAST(NULL AS INT) AS PCAge
                FROM TSMDM_ASSET mdm WITH (NOLOCK)
                ${mdmRelationJoin}
                ${relationJoin}
                WHERE ISNULL(mdm.MDM_Asset_Idn, 0) > 0
                  ${mappingExclude}
            `);
        }
    }

    if (parts.length === 0) return [];

    const result = await pool.request()
        .input("Limit", sql.Int, limit)
        .input("RelationID", sql.Int, relationID)
        .input("SearchText", sql.NVarChar(255), searchText)
        .query(`
            ;WITH Assets AS (
                ${parts.join("\nUNION ALL\n")}
            )
            SELECT TOP (@Limit) *
            FROM Assets
            WHERE
                @SearchText = ''
                OR ComputerName LIKE '%' + @SearchText + '%'
                OR Object_DeviceID LIKE '%' + @SearchText + '%'
                OR MDM_DeviceID LIKE '%' + @SearchText + '%'
                OR MDM_DeviceName LIKE '%' + @SearchText + '%'
                OR Model LIKE '%' + @SearchText + '%'
                OR PlatformType LIKE '%' + @SearchText + '%'
                OR IP LIKE '%' + @SearchText + '%'
                OR Object_Full_Name LIKE '%' + @SearchText + '%'
            ORDER BY ISNULL(Object_Full_Name, ''), ISNULL(ComputerName, Object_DeviceID), Object_Agent;
        `);

    return (result.recordset || []).map(normalizeDbRowDateValues);
}

async function getAssetsByRelationID(pool, relationID) {
    // Hardware Inventory branch asset list.
    // This is intentionally executed as two independent reads instead of one
    // UNION query. The old combined SQL could force SQL Server into an unstable
    // plan even when a branch returned only one row. Running EM and MDM as
    // separate filtered queries avoids duplicate-removal work and lets each
    // side use its own best index/plan.
    const includeBios = await hasBiosInventoryTables(pool);
    const biosFragments = getBiosSqlFragments("em", "em", includeBios);

    const emQuery = `
SELECT
    em.Object_Root_Idn AS _Idn,
    'EM' AS Object_Agent,
    em.Object_DeviceID,
    em.Object_Root_Idn AS Object_Root_Idn,
    mdmMap.MDM_Asset_Idn AS MDM_Asset_Idn,
    mdmMap.DeviceID AS MDM_DeviceID,
    mdmMap.DeviceName AS MDM_DeviceName,
    em.ComputerName,
    rel.Object_Full_Name,
    'Windows' AS PlatformType,
    em.Model,
    em.ConnectionTime,
    CASE WHEN em.ConnectionStatus = 1 THEN 'Online' ELSE 'Offline' END AS ConnectionStatus,
    em.IP,
    ${biosFragments.select}
FROM TS_OBJECT_ROOT em WITH (NOLOCK)
LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK)
    ON em.Object_Rel_Idn = rel.Object_Rel_Idn
LEFT JOIN TSMDM_TS_OBJECT_MAPPING emMap WITH (NOLOCK)
    ON em.Object_Root_Idn = emMap.Object_Root_Idn
LEFT JOIN TSMDM_ASSET mdmMap WITH (NOLOCK)
    ON emMap.MDM_Asset_Idn = mdmMap.MDM_Asset_Idn
${biosFragments.join}
WHERE em.Object_Rel_Idn = @RelationID;
    `;

    const mdmQuery = `
SELECT
    mdm.MDM_Asset_Idn AS _Idn,
    'MDM' AS Object_Agent,
    mdm.DeviceID AS Object_DeviceID,
    CAST(NULL AS INT) AS Object_Root_Idn,
    mdm.MDM_Asset_Idn AS MDM_Asset_Idn,
    mdm.DeviceID AS MDM_DeviceID,
    mdm.DeviceName AS MDM_DeviceName,
    mdm.DeviceName AS ComputerName,
    rel.Object_Full_Name,
    ISNULL(NULLIF(mdm.PlatformType, ''), 'MDM') AS PlatformType,
    mdm.DeviceModelName AS Model,
    mdm.DeviceTimeStamp AS ConnectionTime,
    ISNULL(NULLIF(CAST(mdm.ConnectionStatus AS NVARCHAR(100)), ''), 'Unknown') AS ConnectionStatus,
    CASE
        WHEN mdm.DeviceLocalIPAddress IS NULL OR mdm.DeviceLocalIPAddress = '' THEN mdm.DeviceIPAddress
        ELSE mdm.DeviceLocalIPAddress
    END AS IP,
    CAST(NULL AS NVARCHAR(100)) AS BiosDate,
    CAST(NULL AS INT) AS PCAge
FROM TSMDM_OBJECT_RELATION mor WITH (NOLOCK)
INNER JOIN TSMDM_ASSET mdm WITH (NOLOCK)
    ON mdm.MDM_Asset_Idn = mor.MDM_Asset_Idn
LEFT JOIN TS_OBJECT_RELATION rel WITH (NOLOCK)
    ON mor.Object_Rel_Idn = rel.Object_Rel_Idn
WHERE mor.Object_Rel_Idn = @RelationID
AND NOT EXISTS (
    SELECT 1
    FROM TSMDM_TS_OBJECT_MAPPING map WITH (NOLOCK)
    WHERE map.MDM_Asset_Idn = mdm.MDM_Asset_Idn
);
    `;

    const [emResult, mdmResult] = await Promise.all([
        pool.request().input("RelationID", sql.Int, relationID).query(emQuery),
        pool.request().input("RelationID", sql.Int, relationID).query(mdmQuery)
    ]);

    const rows = [
        ...getSafeRecordset(emResult),
        ...getSafeRecordset(mdmResult)
    ];

    rows.sort((a, b) => {
        const branchA = String(a.Object_Full_Name || '');
        const branchB = String(b.Object_Full_Name || '');
        if (branchA !== branchB) return branchA.localeCompare(branchB);
        const nameA = String(a.ComputerName || a.Object_DeviceID || '');
        const nameB = String(b.ComputerName || b.Object_DeviceID || '');
        if (nameA !== nameB) return nameA.localeCompare(nameB);
        return String(a.Object_Agent || '').localeCompare(String(b.Object_Agent || ''));
    });

    return rows.map(cloneDbRow);
}

// GET /api/departments


// HARDWARE INVENTORY - DEPARTMENT/FOLDER CRUD
// Used by Hardware.tsx folder actions:
// POST /api/departments
// PUT /api/departments/:relationID
// DELETE /api/departments/:relationID
function normalizeDepartmentName(value) {
    return String(value || "").trim();
}

function parseDepartmentRelationId(value, fallback = 0) {
    const parsed = parseInt(value, 10);
    return Number.isNaN(parsed) ? fallback : parsed;
}

function quoteSqlIdentifier(name) {
    return `[${String(name || '').replace(/]/g, ']]')}]`;
}

function normalizeDepartmentColumnKey(name) {
    return String(name || '').toLowerCase();
}

async function getDepartmentById(pool, relationID) {
    const result = await pool.request()
        .input("Object_Rel_Idn", sql.Int, relationID)
        .query(`
            SELECT TOP 1
                Object_Rel_Idn,
                Object_Rel_Name,
                Object_Full_Name,
                Object_PR_Idn,
                Object_Rel_Code,
                Object_Rel_Deleted
            FROM TS_OBJECT_RELATION WITH (NOLOCK)
            WHERE Object_Rel_Idn = @Object_Rel_Idn
              AND ISNULL(Object_Rel_Deleted, 0) = 0;
        `);

    return getSafeRecordset(result)[0] || null;
}

async function getDepartmentTableColumns(pool) {
    const result = await pool.request().query(`
        SELECT
            c.name AS columnName,
            t.name AS typeName,
            c.max_length AS maxLength,
            c.precision AS precisionValue,
            c.scale AS scaleValue,
            c.is_nullable AS isNullable,
            c.is_identity AS isIdentity,
            dc.definition AS defaultDefinition
        FROM sys.columns c
        INNER JOIN sys.types t
            ON c.user_type_id = t.user_type_id
        LEFT JOIN sys.default_constraints dc
            ON c.default_object_id = dc.object_id
        WHERE c.object_id = OBJECT_ID(N'TS_OBJECT_RELATION')
        ORDER BY c.column_id;
    `);

    return getSafeRecordset(result);
}

function getDepartmentColumn(columns, name) {
    const target = normalizeDepartmentColumnKey(name);
    return (columns || []).find((column) => normalizeDepartmentColumnKey(column.columnName) === target) || null;
}

function getDepartmentSqlInputType(column) {
    const typeName = normalizeDepartmentColumnKey(column?.typeName);
    const maxLength = Number(column?.maxLength || 0);
    const precision = Number(column?.precisionValue || 18);
    const scale = Number(column?.scaleValue || 0);

    switch (typeName) {
        case 'bigint': return sql.BigInt;
        case 'bit': return sql.Bit;
        case 'date': return sql.Date;
        case 'datetime': return sql.DateTime;
        case 'datetime2': return sql.DateTime2;
        case 'smalldatetime': return sql.SmallDateTime;
        case 'decimal':
        case 'numeric': return sql.Decimal(precision || 18, scale || 0);
        case 'float': return sql.Float;
        case 'int': return sql.Int;
        case 'money': return sql.Money;
        case 'real': return sql.Real;
        case 'smallint': return sql.SmallInt;
        case 'smallmoney': return sql.SmallMoney;
        case 'tinyint': return sql.TinyInt;
        case 'uniqueidentifier': return sql.UniqueIdentifier;
        case 'varchar': return sql.VarChar(maxLength === -1 ? sql.MAX : Math.max(1, maxLength || 255));
        case 'char': return sql.Char(Math.max(1, maxLength || 1));
        case 'nvarchar': return sql.NVarChar(maxLength === -1 ? sql.MAX : Math.max(1, Math.floor((maxLength || 510) / 2)));
        case 'nchar': return sql.NChar(Math.max(1, Math.floor((maxLength || 2) / 2)));
        default: return sql.NVarChar(sql.MAX);
    }
}

function getDepartmentFallbackValue(column) {
    const typeName = normalizeDepartmentColumnKey(column?.typeName);
    const columnName = normalizeDepartmentColumnKey(column?.columnName);

    if (columnName.includes('date') || columnName.includes('time')) return new Date();

    if (['bigint', 'decimal', 'float', 'int', 'money', 'numeric', 'real', 'smallint', 'smallmoney', 'tinyint'].includes(typeName)) return 0;
    if (typeName === 'bit') return 0;
    if (typeName === 'date' || typeName === 'datetime' || typeName === 'datetime2' || typeName === 'smalldatetime') return new Date();
    if (typeName === 'uniqueidentifier') return typeof crypto.randomUUID === 'function' ? crypto.randomUUID() : crypto.randomBytes(16).toString('hex');
    return '';
}

async function getNextDepartmentRelationId(pool) {
    const result = await pool.request().query(`
        SELECT ISNULL(MAX(Object_Rel_Idn), 0) + 1 AS nextRelationID
        FROM TS_OBJECT_RELATION WITH (UPDLOCK, HOLDLOCK);
    `);

    return Number(getSafeRecordset(result)[0]?.nextRelationID || 1);
}

async function buildDepartmentFullName(pool, parentID, name) {
    const cleanName = normalizeDepartmentName(name);
    if (!cleanName) return "";
    if (parentID === -1 || parentID === 0 || parentID === null || parentID === undefined) return cleanName;

    const parent = await getDepartmentById(pool, parentID);
    if (!parent) return cleanName;

    const parentFullName = normalizeDepartmentName(parent.Object_Full_Name || parent.Object_Rel_Name);
    return parentFullName ? `${parentFullName} > ${cleanName}` : cleanName;
}

async function refreshDepartmentDescendantFullNames(pool, relationID) {
    await pool.request()
        .input("RootRelationID", sql.Int, relationID)
        .query(`
            ;WITH DepartmentTree AS (
                SELECT
                    child.Object_Rel_Idn,
                    child.Object_Rel_Name,
                    child.Object_PR_Idn,
                    CAST(
                        CASE
                            WHEN parent.Object_Rel_Idn IS NULL THEN child.Object_Rel_Name
                            WHEN NULLIF(parent.Object_Full_Name, '') IS NULL THEN child.Object_Rel_Name
                            ELSE parent.Object_Full_Name + ' > ' + child.Object_Rel_Name
                        END AS NVARCHAR(1000)
                    ) AS NextFullName
                FROM TS_OBJECT_RELATION child
                LEFT JOIN TS_OBJECT_RELATION parent
                    ON parent.Object_Rel_Idn = child.Object_PR_Idn
                WHERE child.Object_PR_Idn = @RootRelationID
                  AND ISNULL(child.Object_Rel_Deleted, 0) = 0

                UNION ALL

                SELECT
                    nextChild.Object_Rel_Idn,
                    nextChild.Object_Rel_Name,
                    nextChild.Object_PR_Idn,
                    CAST(dt.NextFullName + ' > ' + nextChild.Object_Rel_Name AS NVARCHAR(1000)) AS NextFullName
                FROM TS_OBJECT_RELATION nextChild
                INNER JOIN DepartmentTree dt
                    ON nextChild.Object_PR_Idn = dt.Object_Rel_Idn
                WHERE ISNULL(nextChild.Object_Rel_Deleted, 0) = 0
            )
            UPDATE rel
            SET Object_Full_Name = dt.NextFullName
            FROM TS_OBJECT_RELATION rel
            INNER JOIN DepartmentTree dt
                ON dt.Object_Rel_Idn = rel.Object_Rel_Idn;
        `);
}

function normalizeDepartmentCodeText(value) {
    return String(value || "").trim();
}

function makeTemporaryDepartmentCode(name) {
    const slug = String(name || "BRANCH")
        .trim()
        .toUpperCase()
        .replace(/[^A-Z0-9]+/g, "-")
        .replace(/^-+|-+$/g, "")
        .slice(0, 32) || "BRANCH";
    return `TMP-${slug}-${Date.now()}-${crypto.randomBytes(3).toString("hex").toUpperCase()}`;
}

async function buildDepartmentRelationCode(pool, parentID, relationID) {
    const cleanRelationID = parseDepartmentRelationId(relationID, 0);
    const cleanParentID = parseDepartmentRelationId(parentID, -1);
    if (!cleanRelationID) return makeTemporaryDepartmentCode("branch");

    if (cleanParentID <= 0) return `-${cleanRelationID}-`;

    const parentResult = await pool.request()
        .input("Object_Rel_Idn", sql.Int, cleanParentID)
        .query(`
            SELECT TOP 1 Object_Rel_Code
            FROM TS_OBJECT_RELATION WITH (NOLOCK)
            WHERE Object_Rel_Idn = @Object_Rel_Idn
              AND ISNULL(Object_Rel_Deleted, 0) = 0;
        `);

    const parentCode = normalizeDepartmentCodeText(getSafeRecordset(parentResult)[0]?.Object_Rel_Code);
    if (parentCode) {
        return parentCode.endsWith("-") ? `${parentCode}${cleanRelationID}-` : `${parentCode}-${cleanRelationID}-`;
    }

    return `-${cleanParentID}-${cleanRelationID}-`;
}

async function insertDepartmentRow(pool, { name, fullName, parentID }) {
    const columns = await getDepartmentTableColumns(pool);
    if (!Array.isArray(columns) || columns.length === 0) {
        const error = new Error('TS_OBJECT_RELATION table metadata could not be read.');
        error.statusCode = 500;
        throw error;
    }

    const values = new Map();
    const setValue = (columnName, value) => {
        const column = getDepartmentColumn(columns, columnName);
        if (!column || column.isIdentity === true || column.isIdentity === 1) return;
        values.set(column.columnName, { column, value });
    };

    const relationColumn = getDepartmentColumn(columns, 'Object_Rel_Idn');
    let plannedRelationID = 0;
    if (relationColumn && !(relationColumn.isIdentity === true || relationColumn.isIdentity === 1)) {
        plannedRelationID = await getNextDepartmentRelationId(pool);
        setValue('Object_Rel_Idn', plannedRelationID);
    }

    const hasObjectRelCode = Boolean(getDepartmentColumn(columns, 'Object_Rel_Code'));
    const temporaryObjectRelCode = hasObjectRelCode
        ? (plannedRelationID ? await buildDepartmentRelationCode(pool, parentID, plannedRelationID) : makeTemporaryDepartmentCode(name))
        : '';

    setValue('Object_Rel_Name', name);
    setValue('Object_Full_Name', fullName);
    setValue('Object_PR_Idn', parentID);
    setValue('Object_Rel_Deleted', 0);
    if (hasObjectRelCode) setValue('Object_Rel_Code', temporaryObjectRelCode);

    for (const column of columns) {
        const columnName = column.columnName;
        if (values.has(columnName)) continue;
        if (column.isIdentity === true || column.isIdentity === 1) continue;
        if (column.isNullable === true || column.isNullable === 1) continue;
        if (column.defaultDefinition) continue;

        setValue(columnName, getDepartmentFallbackValue(column));
    }

    const insertColumns = [...values.keys()];
    if (insertColumns.length === 0) {
        const error = new Error('No insertable columns were found for TS_OBJECT_RELATION.');
        error.statusCode = 500;
        throw error;
    }

    const request = pool.request();
    const valueParams = insertColumns.map((columnName, index) => {
        const entry = values.get(columnName);
        const paramName = `DeptCol${index}`;
        request.input(paramName, getDepartmentSqlInputType(entry.column), entry.value);
        return `@${paramName}`;
    });

    const returnColumnNames = ['Object_Rel_Idn', 'Object_Rel_Name', 'Object_Full_Name', 'Object_PR_Idn', 'Object_Rel_Code']
        .filter((columnName) => getDepartmentColumn(columns, columnName));

    const outputColumns = returnColumnNames
        .map((columnName) => `INSERTED.${quoteSqlIdentifier(columnName)}`)
        .join(',\n                    ');

    const selectColumns = returnColumnNames
        .map((columnName) => quoteSqlIdentifier(columnName))
        .join(',\n                ');

    const result = await request.query(`
        INSERT INTO TS_OBJECT_RELATION
        (
            ${insertColumns.map(quoteSqlIdentifier).join(',\n            ')}
        )
        OUTPUT
            ${outputColumns}
        VALUES
        (
            ${valueParams.join(',\n            ')}
        );
    `);

    let row = getSafeRecordset(result)[0] || null;
    const createdRelationID = Number(row?.Object_Rel_Idn || plannedRelationID || values.get('Object_Rel_Idn')?.value || 0);

    if (hasObjectRelCode && createdRelationID > 0) {
        const finalObjectRelCode = await buildDepartmentRelationCode(pool, parentID, createdRelationID);
        if (finalObjectRelCode && finalObjectRelCode !== temporaryObjectRelCode) {
            await pool.request()
                .input('Object_Rel_Idn', sql.Int, createdRelationID)
                .input('Object_Rel_Code', getDepartmentSqlInputType(getDepartmentColumn(columns, 'Object_Rel_Code')), finalObjectRelCode)
                .query(`
                    UPDATE TS_OBJECT_RELATION
                    SET Object_Rel_Code = @Object_Rel_Code
                    WHERE Object_Rel_Idn = @Object_Rel_Idn;
                `);
        }
    }

    if (createdRelationID > 0) {
        const reloadResult = await pool.request()
            .input('Object_Rel_Idn', sql.Int, createdRelationID)
            .query(`
                SELECT TOP 1
                    ${selectColumns}
                FROM TS_OBJECT_RELATION WITH (NOLOCK)
                WHERE Object_Rel_Idn = @Object_Rel_Idn;
            `);

        row = getSafeRecordset(reloadResult)[0] || row;
    }

    return row;
}
app.post("/api/departments", authenticateToken, async (req, res) => {
    try {
        const name = normalizeDepartmentName(req.body?.name || req.body?.Object_Rel_Name || req.body?.departmentName);
        const parentID = parseDepartmentRelationId(req.body?.parentID ?? req.body?.parentId ?? req.body?.Object_PR_Idn, -1);

        if (!name) {
            return res.status(400).json({ success: false, message: "Branch name is required." });
        }

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);

        if (parentID !== -1) {
            const parent = await getDepartmentById(pool, parentID);
            if (!parent) {
                return res.status(404).json({ success: false, message: `Parent branch '${parentID}' was not found.` });
            }
        }

        const duplicateResult = await pool.request()
            .input("ParentID", sql.Int, parentID)
            .input("Name", sql.NVarChar(255), name)
            .query(`
                SELECT TOP 1 Object_Rel_Idn
                FROM TS_OBJECT_RELATION WITH (NOLOCK)
                WHERE ISNULL(Object_Rel_Deleted, 0) = 0
                  AND Object_PR_Idn = @ParentID
                  AND LOWER(Object_Rel_Name) = LOWER(@Name);
            `);

        if (getSafeRecordset(duplicateResult).length > 0) {
            return res.status(409).json({ success: false, message: "A branch with the same name already exists under this parent." });
        }

        const fullName = await buildDepartmentFullName(pool, parentID, name);
        const row = await insertDepartmentRow(pool, { name, fullName, parentID });

        if (!row) {
            return res.status(500).json({ success: false, message: "Branch was created but the new row could not be read." });
        }

        clearHardwareInventoryCache();
        return res.json({ success: true, data: row, message: "Branch created successfully." });
    } catch (err) {
        console.error("POST /api/departments error:", err);
        return res.status(err.statusCode || 500).json({
            success: false,
            message: "Failed to create branch",
            error: err.message,
            details: err.originalError?.info?.message || err.precedingErrors?.map((item) => item.message).join(' | ') || undefined
        });
    }
});

app.put("/api/departments/:relationID", authenticateToken, async (req, res) => {
    try {
        const relationID = parseDepartmentRelationId(req.params.relationID, 0);
        const name = normalizeDepartmentName(req.body?.name || req.body?.Object_Rel_Name || req.body?.departmentName);

        if (!relationID) {
            return res.status(400).json({ success: false, message: "Invalid branch ID." });
        }

        if (!name) {
            return res.status(400).json({ success: false, message: "Branch name is required." });
        }

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        const current = await getDepartmentById(pool, relationID);

        if (!current) {
            return res.status(404).json({ success: false, message: `Branch '${relationID}' was not found.` });
        }

        const parentID = parseDepartmentRelationId(current.Object_PR_Idn, -1);
        const duplicateResult = await pool.request()
            .input("RelationID", sql.Int, relationID)
            .input("ParentID", sql.Int, parentID)
            .input("Name", sql.NVarChar(255), name)
            .query(`
                SELECT TOP 1 Object_Rel_Idn
                FROM TS_OBJECT_RELATION WITH (NOLOCK)
                WHERE ISNULL(Object_Rel_Deleted, 0) = 0
                  AND Object_Rel_Idn <> @RelationID
                  AND Object_PR_Idn = @ParentID
                  AND LOWER(Object_Rel_Name) = LOWER(@Name);
            `);

        if (getSafeRecordset(duplicateResult).length > 0) {
            return res.status(409).json({ success: false, message: "A branch with the same name already exists under this parent." });
        }

        const fullName = await buildDepartmentFullName(pool, parentID, name);
        const updateResult = await pool.request()
            .input("Object_Rel_Idn", sql.Int, relationID)
            .input("Object_Rel_Name", sql.NVarChar(255), name)
            .input("Object_Full_Name", sql.NVarChar(1000), fullName)
            .query(`
                UPDATE TS_OBJECT_RELATION
                SET Object_Rel_Name = @Object_Rel_Name,
                    Object_Full_Name = @Object_Full_Name
                OUTPUT
                    INSERTED.Object_Rel_Idn,
                    INSERTED.Object_Rel_Name,
                    INSERTED.Object_Full_Name,
                    INSERTED.Object_PR_Idn
                WHERE Object_Rel_Idn = @Object_Rel_Idn
                  AND ISNULL(Object_Rel_Deleted, 0) = 0;
            `);

        const row = getSafeRecordset(updateResult)[0];
        await refreshDepartmentDescendantFullNames(pool, relationID);

        clearHardwareInventoryCache();
        return res.json({ success: true, data: row, message: "Branch renamed successfully." });
    } catch (err) {
        console.error("PUT /api/departments/:relationID error:", err);
        return res.status(500).json({ success: false, message: "Failed to rename branch", error: err.message });
    }
});

app.delete("/api/departments/:relationID", authenticateToken, async (req, res) => {
    try {
        const relationID = parseDepartmentRelationId(req.params.relationID, 0);
        const forceDelete = String(req.query.force || req.body?.force || "").toLowerCase() === "true" || String(req.query.force || req.body?.force || "") === "1";

        if (!relationID) {
            return res.status(400).json({ success: false, message: "Invalid branch ID." });
        }

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        const current = await getDepartmentById(pool, relationID);

        if (!current) {
            return res.status(404).json({ success: false, message: `Branch '${relationID}' was not found.` });
        }

        const usageResult = await pool.request()
            .input("Object_Rel_Idn", sql.Int, relationID)
            .query(`
                SELECT
                    (SELECT COUNT(1)
                     FROM TS_OBJECT_RELATION WITH (NOLOCK)
                     WHERE Object_PR_Idn = @Object_Rel_Idn
                       AND ISNULL(Object_Rel_Deleted, 0) = 0) AS childCount,
                    (SELECT COUNT(1)
                     FROM TS_OBJECT_ROOT WITH (NOLOCK)
                     WHERE Object_Rel_Idn = @Object_Rel_Idn) AS emAssetCount,
                    (SELECT COUNT(1)
                     FROM TSMDM_OBJECT_RELATION WITH (NOLOCK)
                     WHERE Object_Rel_Idn = @Object_Rel_Idn) AS mdmAssetCount;
            `);

        const usage = getSafeRecordset(usageResult)[0] || {};
        const childCount = Number(usage.childCount || 0);
        const emAssetCount = Number(usage.emAssetCount || 0);
        const mdmAssetCount = Number(usage.mdmAssetCount || 0);

        if (!forceDelete && (childCount > 0 || emAssetCount > 0 || mdmAssetCount > 0)) {
            return res.status(409).json({
                success: false,
                message: "This branch still has sub-branches or assigned devices. Move/delete them first before deleting the branch.",
                data: { childCount, emAssetCount, mdmAssetCount }
            });
        }

        if (forceDelete) {
            await pool.request()
                .input("Object_Rel_Idn", sql.Int, relationID)
                .input("FallbackParentID", sql.Int, parseDepartmentRelationId(current.Object_PR_Idn, -1))
                .query(`
                    UPDATE TS_OBJECT_ROOT
                    SET Object_Rel_Idn = @FallbackParentID
                    WHERE Object_Rel_Idn = @Object_Rel_Idn;

                    UPDATE TSMDM_OBJECT_RELATION
                    SET Object_Rel_Idn = @FallbackParentID
                    WHERE Object_Rel_Idn = @Object_Rel_Idn;
                `);
        }

        const deleteResult = await pool.request()
            .input("Object_Rel_Idn", sql.Int, relationID)
            .query(`
                UPDATE TS_OBJECT_RELATION
                SET Object_Rel_Deleted = 1
                OUTPUT
                    DELETED.Object_Rel_Idn,
                    DELETED.Object_Rel_Name,
                    DELETED.Object_Full_Name,
                    DELETED.Object_PR_Idn
                WHERE Object_Rel_Idn = @Object_Rel_Idn
                  AND ISNULL(Object_Rel_Deleted, 0) = 0;
            `);

        const row = getSafeRecordset(deleteResult)[0];
        clearHardwareInventoryCache();
        return res.json({ success: true, data: row, message: "Branch deleted successfully." });
    } catch (err) {
        console.error("DELETE /api/departments/:relationID error:", err);
        return res.status(500).json({ success: false, message: "Failed to delete branch", error: err.message });
    }
});


