app.post('/api/incidents/search', authenticateToken, async (req, res) => {
    try {
        const {
            keyword,
            dateRange,
            incidentType,
            statuses,
            asset,
            assignment,
            slaStatus
        } = req.body;

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        let query = `
            SELECT 
                IncidentID as id,
                Title as title,
                Description as description,
                Priority as priority,
                CASE WHEN Status = 'Solved' THEN 'Resolved' ELSE Status END as status,
                Category as category,
                CreatedAt as createdAt,
                RequesterID as requesterId,
                RequesterName as requesterName,
                DeviceType as deviceType,
                AssetID as assetId,
                Subcategory as subcategory,
                IncidentDetail as incidentDetail,
                ReporterID as reporterId,
                SlaDue as slaDue,
                AssignedTo as assignedTo,
                AssignedLevel as assignedLevel,
                FirstResponseAt as firstResponseAt,
                ResolvedAt as resolvedAt,
                RootCause as rootCause,
                ActionPlan as actionPlan,
                AdditionalMemo as additionalMemo
            FROM EMA_Incidents
            WHERE 1=1
        `;
        
        const conditions = [];
        const request = pool.request();
        let paramCounter = 1;

        // 1. Keyword Search
        if (keyword) {
            if (keyword.reqNo) {
                conditions.push(`IncidentID LIKE @reqNo${paramCounter}`);
                request.input(`reqNo${paramCounter}`, sql.NVarChar, `%${keyword.reqNo}%`);
                paramCounter++;
            }
            if (keyword.requester) {
                conditions.push(`RequesterName LIKE @requester${paramCounter}`);
                request.input(`requester${paramCounter}`, sql.NVarChar, `%${keyword.requester}%`);
                paramCounter++;
            }
            if (keyword.incidentTitle) {
                conditions.push(`Title LIKE @title${paramCounter}`);
                request.input(`title${paramCounter}`, sql.NVarChar, `%${keyword.incidentTitle}%`);
                paramCounter++;
            }
            if (keyword.assetTag) {
                conditions.push(`AssetID LIKE @assetTag${paramCounter}`);
                request.input(`assetTag${paramCounter}`, sql.NVarChar, `%${keyword.assetTag}%`);
                paramCounter++;
            }
            // IP address filter removed because legacy asset table is no longer used.
        }

        // 2. Date Range
        if (dateRange && dateRange.type === 'custom') {
            if (dateRange.startDate) {
                conditions.push(`CAST(CreatedAt AS DATE) >= @startDate`);
                request.input('startDate', sql.Date, dateRange.startDate);
            }
            if (dateRange.endDate) {
                conditions.push(`CAST(CreatedAt AS DATE) <= @endDate`);
                request.input('endDate', sql.Date, dateRange.endDate);
            }
        }

        // 3. Incident Type (Cascading)
        if (incidentType) {
            if (incidentType.category) {
                conditions.push(`Category = @category`);
                request.input('category', sql.NVarChar, incidentType.category);
            }
            if (incidentType.subcategory) {
                conditions.push(`Subcategory = @subcategory`);
                request.input('subcategory', sql.NVarChar, incidentType.subcategory);
            }
            if (incidentType.detail) {
                conditions.push(`IncidentDetail = @detail`);
                request.input('detail', sql.NVarChar, incidentType.detail);
            }
        }

        // 4. Status Filter (Multiple selection)
        if (statuses && statuses.length > 0) {
            const placeholders = statuses.map((_, i) => `@status${i}`).join(',');
            conditions.push(`Status IN (${placeholders})`);
            statuses.forEach((status, i) => {
                request.input(`status${i}`, sql.NVarChar, status);
            });
        }

        // 5. Asset Information
        if (asset) {
            if (asset.deviceType) {
                conditions.push(`DeviceType = @deviceType`);
                request.input('deviceType', sql.NVarChar, asset.deviceType);
            }
            // Brand/model filter removed because legacy asset table is no longer used.
        }

        // 6. Assignment
        if (assignment) {
            if (assignment.supportLevel && assignment.supportLevel !== 'All') {
                conditions.push(`AssignedLevel = @supportLevel`);
                request.input('supportLevel', sql.NVarChar, assignment.supportLevel);
            }
            if (assignment.engineer) {
                conditions.push(`AssignedTo = @engineer`);
                request.input('engineer', sql.NVarChar, assignment.engineer);
            }
        }

        // 7. SLA Status
        if (slaStatus && slaStatus !== 'All') {
            const now = new Date().toISOString();
            if (slaStatus === 'On Time') {
                conditions.push(`SlaDue IS NOT NULL AND SlaDue > GETDATE() AND Status NOT IN ('Resolved', 'Solved')`);
            } else if (slaStatus === 'Near Due') {
                conditions.push(`SlaDue IS NOT NULL AND SlaDue <= DATEADD(hour, 24, GETDATE()) AND SlaDue > GETDATE() AND Status NOT IN ('Resolved', 'Solved')`);
            } else if (slaStatus === 'Overdue') {
                conditions.push(`SlaDue IS NOT NULL AND SlaDue < GETDATE() AND Status NOT IN ('Resolved', 'Solved')`);
            }
        }

        // Apply all conditions
        if (conditions.length > 0) {
            query += ` AND ${conditions.join(' AND ')}`;
        }

        // Add ordering
        query += ` ORDER BY CreatedAt DESC`;

        console.log('Search Query:', query);
        const result = await request.query(query);
        
        res.json({
            success: true,
            data: result.recordset,
            total: result.recordset.length,
            filters: req.body
        });
        
    } catch (err) {
        console.error('POST /api/incidents/search error:', err);
        res.status(500).json({ 
            success: false, 
            message: 'Failed to search incidents', 
            error: err.message 
        });
    }
});

