app.post("/api/settings/users", authenticateToken, async (req, res) => {
    try {
        const fullName = String(req.body.fullName || req.body.name || "").trim();
        const email = String(req.body.email || "").trim();
        const username = buildEmaUsername(req.body.username, email, fullName);
        const accountLocked = parseEmaBit(req.body.accountLocked, false);
        const status = accountLocked ? "Locked" : normalizeEmaUserStatus(req.body.status);
        const roleNames = getRequestedEmaRoles(req.body);
        const passwordText = String(req.body.password || req.body.newPassword || "").trim();
        const requestedRequireMFA = parseEmaBit(req.body.requireMFA ?? req.body.mfa, false);
        const resetMfaEnrollment = requestedRequireMFA;

        if (!fullName && !username) {
            return res.status(400).json({ success: false, message: "Full name or username is required." });
        }

        if (!passwordText || passwordText.length < 8) {
            return res.status(400).json({ success: false, message: "Password must be at least 8 characters." });
        }

        const passwordHash = await bcrypt.hash(passwordText, 10);

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        await assertEmaUsersTable(pool);

        const duplicate = await pool.request()
            .input("Username", sql.NVarChar, username)
            .input("Email", sql.NVarChar, email)
            .query(`
                SELECT TOP 1 UserID
                FROM EMA_Users WITH (NOLOCK)
                WHERE Username = @Username
                   OR (@Email <> '' AND Email = @Email)
            `);

        if (duplicate.recordset.length > 0) {
            return res.status(409).json({ success: false, message: "Username or email already exists." });
        }

        const result = await pool.request()
            .input("LegacyUserID", sql.Int, req.body.legacyUserID || null)
            .input("Username", sql.NVarChar, username)
            .input("FullName", sql.NVarChar, fullName || username)
            .input("Email", sql.NVarChar, email)
            .input("RoleName", sql.NVarChar, roleNames.join(", "))
            .input("AccessScope", sql.NVarChar, req.body.accessScope || req.body.scope || "EMA + Dashboard")
            .input("Department", sql.NVarChar, req.body.department || "")
            .input("Position", sql.NVarChar, req.body.position || "")
            .input("PhoneNo", sql.NVarChar, req.body.phoneNo || "")
            .input("Status", sql.NVarChar, status)
            .input("IsActive", sql.Bit, status === "Inactive" ? 0 : 1)
            .input("RequireMFA", sql.Bit, requestedRequireMFA ? 1 : 0)
            .input("ResetMfaEnrollment", sql.Bit, resetMfaEnrollment ? 1 : 0)
            .input("AccountLocked", sql.Bit, accountLocked ? 1 : 0)
            .input("LockReason", sql.NVarChar, accountLocked ? (req.body.lockReason || "Locked by administrator") : "")
            .input("AccessStartDate", sql.DateTime, normalizeEmaDate(req.body.accessStartDate))
            .input("AccessEndDate", sql.DateTime, normalizeEmaDate(req.body.accessEndDate))
            .input("LoginFailCount", sql.Int, parseInt(req.body.loginFailCount, 10) || 0)
            .input("Remarks", sql.NVarChar, req.body.remarks || "")
            .input("PasswordHash", sql.NVarChar(255), passwordHash)
            .input("CreatedBy", sql.NVarChar, req.user?.userID || "system")
            .query(`
                INSERT INTO EMA_Users
                (
                    LegacyUserID,
                    Username,
                    FullName,
                    Email,
                    RoleName,
                    AccessScope,
                    Department,
                    Position,
                    PhoneNo,
                    Status,
                    IsActive,
                    RequireMFA,
                    AccountLocked,
                    LockReason,
                    AccessStartDate,
                    AccessEndDate,
                    LoginFailCount,
                    Remarks,
                    PasswordHash,
                    PasswordChangedAt,
                    CreatedAt,
                    CreatedBy
                )
                OUTPUT
                    ${emaUserSelectColumns.replace(/\bUserID\b/g, "INSERTED.UserID").replace(/\bLegacyUserID\b/g, "INSERTED.LegacyUserID").replace(/\bUsername\b/g, "INSERTED.Username").replace(/\bFullName\b/g, "INSERTED.FullName").replace(/\bEmail\b/g, "INSERTED.Email").replace(/\bRoleName\b/g, "INSERTED.RoleName").replace(/\bAccessScope\b/g, "INSERTED.AccessScope").replace(/\bDepartment\b/g, "INSERTED.Department").replace(/\bPosition\b/g, "INSERTED.Position").replace(/\bPhoneNo\b/g, "INSERTED.PhoneNo").replace(/\bStatus\b/g, "INSERTED.Status").replace(/\bIsActive\b/g, "INSERTED.IsActive").replace(/\bRequireMFA\b/g, "INSERTED.RequireMFA").replace(/\bTwoFactorEnabled\b/g, "INSERTED.TwoFactorEnabled").replace(/\bTwoFactorSecret\b/g, "INSERTED.TwoFactorSecret").replace(/\bTwoFactorVerifiedAt\b/g, "INSERTED.TwoFactorVerifiedAt").replace(/\bTwoFactorResetAt\b/g, "INSERTED.TwoFactorResetAt").replace(/\bAccountLocked\b/g, "INSERTED.AccountLocked").replace(/\bLockReason\b/g, "INSERTED.LockReason").replace(/\bAccessStartDate\b/g, "INSERTED.AccessStartDate").replace(/\bAccessEndDate\b/g, "INSERTED.AccessEndDate").replace(/\bLastLoginAt\b/g, "INSERTED.LastLoginAt").replace(/\bPasswordChangedAt\b/g, "INSERTED.PasswordChangedAt").replace(/\bLoginFailCount\b/g, "INSERTED.LoginFailCount").replace(/\bRemarks\b/g, "INSERTED.Remarks").replace(/\bCreatedAt\b/g, "INSERTED.CreatedAt").replace(/\bUpdatedAt\b/g, "INSERTED.UpdatedAt")}
                VALUES
                (
                    @LegacyUserID,
                    @Username,
                    @FullName,
                    @Email,
                    @RoleName,
                    @AccessScope,
                    @Department,
                    @Position,
                    @PhoneNo,
                    @Status,
                    @IsActive,
                    @RequireMFA,
                    @AccountLocked,
                    @LockReason,
                    @AccessStartDate,
                    @AccessEndDate,
                    @LoginFailCount,
                    @Remarks,
                    @PasswordHash,
                    GETDATE(),
                    GETDATE(),
                    @CreatedBy
                )
            `);

        const createdRow = result.recordset[0];
        const assignedRoles = await applyEmaUserRoles(pool, createdRow.UserID, roleNames, req.user?.userID || "system");
        const data = mapEmaUserResponse({ ...createdRow, RoleNames: assignedRoles.join(", ") });
        await logEmaAudit(pool, req, "Created EMA user", "User Access Management", "Success", data);
        return res.json({ success: true, data });
    } catch (err) {
        console.error("POST /api/settings/users error:", err);
        return res.status(err.statusCode || 500).json({ success: false, message: err.message });
    }
});

app.put("/api/settings/users/:id", authenticateToken, async (req, res) => {
    try {
        const userID = parseInt(req.params.id, 10);
        if (!userID) {
            return res.status(400).json({ success: false, message: "Invalid user ID." });
        }

        const fullName = String(req.body.fullName || req.body.name || "").trim();
        const email = String(req.body.email || "").trim();
        const username = buildEmaUsername(req.body.username, email, fullName);
        const accountLocked = parseEmaBit(req.body.accountLocked, false);
        const status = accountLocked ? "Locked" : normalizeEmaUserStatus(req.body.status);
        const roleNames = getRequestedEmaRoles(req.body);
        const passwordText = String(req.body.password || req.body.newPassword || "").trim();

        if (passwordText && passwordText.length < 8) {
            return res.status(400).json({ success: false, message: "Password must be at least 8 characters." });
        }

        const passwordHash = passwordText ? await bcrypt.hash(passwordText, 10) : null;
        const requestedRequireMFA = parseEmaBit(req.body.requireMFA ?? req.body.mfa, false);

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        await assertEmaUsersTable(pool);

        const duplicate = await pool.request()
            .input("UserID", sql.Int, userID)
            .input("Username", sql.NVarChar, username)
            .input("Email", sql.NVarChar, email)
            .query(`
                SELECT TOP 1 UserID
                FROM EMA_Users WITH (NOLOCK)
                WHERE UserID <> @UserID
                  AND (
                    Username = @Username
                    OR (@Email <> '' AND Email = @Email)
                  )
            `);

        if (duplicate.recordset.length > 0) {
            return res.status(409).json({ success: false, message: "Username or email already exists." });
        }

        const currentUserResult = await pool.request()
            .input("UserID", sql.Int, userID)
            .query(`
                SELECT TOP 1 RequireMFA, TwoFactorEnabled, TwoFactorSecret
                FROM EMA_Users WITH (NOLOCK)
                WHERE UserID = @UserID;
            `);

        if (currentUserResult.recordset.length === 0) {
            return res.status(404).json({ success: false, message: "User not found." });
        }

        const currentRequireMFA = currentUserResult.recordset[0].RequireMFA === true || currentUserResult.recordset[0].RequireMFA === 1;
        const resetMfaEnrollment = !requestedRequireMFA || (requestedRequireMFA && !currentRequireMFA);

        const passwordUpdateClause = passwordHash
            ? `,
                    PasswordHash = @PasswordHash,
                    PasswordChangedAt = GETDATE()`
            : "";

        const updateUserRequest = pool.request()
            .input("UserID", sql.Int, userID)
            .input("Username", sql.NVarChar, username)
            .input("FullName", sql.NVarChar, fullName || username)
            .input("Email", sql.NVarChar, email)
            .input("RoleName", sql.NVarChar, roleNames.join(", "))
            .input("AccessScope", sql.NVarChar, req.body.accessScope || req.body.scope || "EMA + Dashboard")
            .input("Department", sql.NVarChar, req.body.department || "")
            .input("Position", sql.NVarChar, req.body.position || "")
            .input("PhoneNo", sql.NVarChar, req.body.phoneNo || "")
            .input("Status", sql.NVarChar, status)
            .input("IsActive", sql.Bit, status === "Inactive" ? 0 : 1)
            .input("RequireMFA", sql.Bit, requestedRequireMFA ? 1 : 0)
            .input("ResetMfaEnrollment", sql.Bit, resetMfaEnrollment ? 1 : 0)
            .input("AccountLocked", sql.Bit, accountLocked ? 1 : 0)
            .input("LockReason", sql.NVarChar, accountLocked ? (req.body.lockReason || "Locked by administrator") : "")
            .input("AccessStartDate", sql.DateTime, normalizeEmaDate(req.body.accessStartDate))
            .input("AccessEndDate", sql.DateTime, normalizeEmaDate(req.body.accessEndDate))
            .input("LoginFailCount", sql.Int, parseInt(req.body.loginFailCount, 10) || 0)
            .input("Remarks", sql.NVarChar, req.body.remarks || "")
            .input("UpdatedBy", sql.NVarChar, req.user?.userID || "system");

        if (passwordHash) {
            updateUserRequest.input("PasswordHash", sql.NVarChar(255), passwordHash);
        }

        const result = await updateUserRequest.query(`
                UPDATE EMA_Users
                SET
                    Username = @Username,
                    FullName = @FullName,
                    Email = @Email,
                    RoleName = @RoleName,
                    AccessScope = @AccessScope,
                    Department = @Department,
                    Position = @Position,
                    PhoneNo = @PhoneNo,
                    Status = @Status,
                    IsActive = @IsActive,
                    RequireMFA = @RequireMFA,
                    TwoFactorEnabled = CASE WHEN @ResetMfaEnrollment = 1 THEN 0 ELSE TwoFactorEnabled END,
                    TwoFactorSecret = CASE WHEN @ResetMfaEnrollment = 1 THEN NULL ELSE TwoFactorSecret END,
                    TwoFactorVerifiedAt = CASE WHEN @ResetMfaEnrollment = 1 THEN NULL ELSE TwoFactorVerifiedAt END,
                    TwoFactorResetAt = CASE WHEN @ResetMfaEnrollment = 1 THEN GETDATE() ELSE TwoFactorResetAt END,
                    AccountLocked = @AccountLocked,
                    LockReason = @LockReason,
                    AccessStartDate = @AccessStartDate,
                    AccessEndDate = @AccessEndDate,
                    LoginFailCount = @LoginFailCount,
                    Remarks = @Remarks${passwordUpdateClause},
                    UpdatedAt = GETDATE(),
                    UpdatedBy = @UpdatedBy
                OUTPUT
                    ${emaUserSelectColumns.replace(/\bUserID\b/g, "INSERTED.UserID").replace(/\bLegacyUserID\b/g, "INSERTED.LegacyUserID").replace(/\bUsername\b/g, "INSERTED.Username").replace(/\bFullName\b/g, "INSERTED.FullName").replace(/\bEmail\b/g, "INSERTED.Email").replace(/\bRoleName\b/g, "INSERTED.RoleName").replace(/\bAccessScope\b/g, "INSERTED.AccessScope").replace(/\bDepartment\b/g, "INSERTED.Department").replace(/\bPosition\b/g, "INSERTED.Position").replace(/\bPhoneNo\b/g, "INSERTED.PhoneNo").replace(/\bStatus\b/g, "INSERTED.Status").replace(/\bIsActive\b/g, "INSERTED.IsActive").replace(/\bRequireMFA\b/g, "INSERTED.RequireMFA").replace(/\bTwoFactorEnabled\b/g, "INSERTED.TwoFactorEnabled").replace(/\bTwoFactorSecret\b/g, "INSERTED.TwoFactorSecret").replace(/\bTwoFactorVerifiedAt\b/g, "INSERTED.TwoFactorVerifiedAt").replace(/\bTwoFactorResetAt\b/g, "INSERTED.TwoFactorResetAt").replace(/\bAccountLocked\b/g, "INSERTED.AccountLocked").replace(/\bLockReason\b/g, "INSERTED.LockReason").replace(/\bAccessStartDate\b/g, "INSERTED.AccessStartDate").replace(/\bAccessEndDate\b/g, "INSERTED.AccessEndDate").replace(/\bLastLoginAt\b/g, "INSERTED.LastLoginAt").replace(/\bPasswordChangedAt\b/g, "INSERTED.PasswordChangedAt").replace(/\bLoginFailCount\b/g, "INSERTED.LoginFailCount").replace(/\bRemarks\b/g, "INSERTED.Remarks").replace(/\bCreatedAt\b/g, "INSERTED.CreatedAt").replace(/\bUpdatedAt\b/g, "INSERTED.UpdatedAt")}
                WHERE UserID = @UserID
            `);

        if (result.recordset.length === 0) {
            return res.status(404).json({ success: false, message: "User not found." });
        }

        const updatedRow = result.recordset[0];
        const assignedRoles = await applyEmaUserRoles(pool, updatedRow.UserID, roleNames, req.user?.userID || "system");
        const data = mapEmaUserResponse({ ...updatedRow, RoleNames: assignedRoles.join(", ") });
        await logEmaAudit(pool, req, "Updated EMA user", "User Access Management", "Success", data);
        return res.json({ success: true, data });
    } catch (err) {
        console.error("PUT /api/settings/users/:id error:", err);
        return res.status(err.statusCode || 500).json({ success: false, message: err.message });
    }
});

