/*
|--------------------------------------------------------------------------
| MDM / SureMDM Geolocation APIs + Background Workers
|--------------------------------------------------------------------------
| Frontend APIs read from TSMDM_GEOLOCATION.
| Background workers keep TSMDM_GEOLOCATION populated from SureMDM /v2/location
| and backfill missing LocationName values using the self-hosted Nominatim reverse geocode gateway.
|--------------------------------------------------------------------------
*/


function parseMdmBoolean(value, fallback = false) {
    if (value === undefined || value === null || value === "") return fallback;
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value !== 0;

    const text = String(value).trim().toLowerCase();
    if (["true", "1", "yes", "y", "on"].includes(text)) return true;
    if (["false", "0", "no", "n", "off"].includes(text)) return false;
    return fallback;
}

function parseGeoDate(value, fallback = null) {
    if (!value) return fallback;
    if (value instanceof Date) return Number.isNaN(value.getTime()) ? fallback : value;

    const raw = String(value).trim();
    if (!raw) return fallback;

    const parsed = new Date(raw);
    if (!Number.isNaN(parsed.getTime())) return parsed;

    const parsedWithUtc = new Date(`${raw}Z`);
    return Number.isNaN(parsedWithUtc.getTime()) ? fallback : parsedWithUtc;
}

function formatGeoDateForSureMdm(date) {
    const parsed = parseGeoDate(date, new Date());
    return parsed.toISOString().replace(/Z$/, "").slice(0, 23);
}

function startOfCurrentYearForSureMdm() {
    const now = new Date();
    return `${now.getFullYear()}-01-01T00:00:00.000`;
}

function roundGeo(value, places = 3) {
    const number = Number(value);
    if (!Number.isFinite(number)) return null;
    const factor = 10 ** places;
    return Math.round(number * factor) / factor;
}

function sleepGeo(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

function getGeoEnvBoolean(name, fallback = false) {
    return parseMdmBoolean(process.env[name], fallback);
}

function getGeoEnvInt(name, fallback, min = 0, max = Number.MAX_SAFE_INTEGER) {
    const parsed = parseInt(process.env[name], 10);
    if (Number.isNaN(parsed)) return fallback;
    return Math.min(Math.max(parsed, min), max);
}

function extractSureMdmLocations(payload) {
    const rows = [];
    const candidates = asSureMdmArray(payload);

    for (const item of candidates) {
        if (!item) continue;

        if (Array.isArray(item.Location)) {
            rows.push(...item.Location);
            continue;
        }

        if (item.data && Array.isArray(item.data)) {
            for (const nested of item.data) {
                if (Array.isArray(nested?.Location)) rows.push(...nested.Location);
                else if (nested?.Latitude !== undefined || nested?.latitude !== undefined) rows.push(nested);
            }
            continue;
        }

        if (item.Latitude !== undefined || item.latitude !== undefined) {
            rows.push(item);
        }
    }

    return rows;
}

function normalizeGeoLocationRow(location, asset = {}) {
    const latitude = firstMdmDefined(location.Latitude, location.latitude, location.Lat, location.lat);
    const longitude = firstMdmDefined(location.Longitude, location.longitude, location.Lon, location.lng, location.long);
    const time = firstMdmDefined(location.Time, location.time, location.DateTime, location.datetime, location.Timestamp, location.timestamp);

    return {
        DeviceID: normalizeMdmValue(firstMdmDefined(location.DeviceID, location.deviceID, asset.DeviceID)),
        Latitude: latitude !== undefined && latitude !== null ? String(latitude) : "",
        Longitude: longitude !== undefined && longitude !== null ? String(longitude) : "",
        Time: parseGeoDate(time, new Date()),
        FloorNo: normalizeMdmValue(firstMdmDefined(location.FloorNo, location.floorNo)),
        ILTDeviceBatteryPercent: normalizeMdmValue(firstMdmDefined(location.ILTDeviceBatteryPercent, location.iltDeviceBatteryPercent)),
        ILTWifiSignalStrength: normalizeMdmValue(firstMdmDefined(location.ILTWifiSignalStrength, location.iltWifiSignalStrength)),
        ILTWifiSSID: normalizeMdmValue(firstMdmDefined(location.ILTWifiSSID, location.iltWifiSSID)),
        IsIndoor: normalizeMdmValue(firstMdmDefined(location.IsIndoor, location.IsIndoorTracking, location.isIndoor)),
        LocationName: normalizeMdmValue(firstMdmDefined(location.LocationName, location.locationName, location.Address, location.address)),
        LocationMode: normalizeMdmValue(firstMdmDefined(location.LocationMode, location.locationMode)),
        IndoorLocationSource: normalizeMdmValue(firstMdmDefined(location.IndoorLocationSource, location.indoorLocationSource)),
        LocationAccuracy: normalizeMdmValue(firstMdmDefined(location.LocationAccuracy, location.locationAccuracy, location.Accuracy, location.accuracy)),
        BuildingId: normalizeMdmValue(firstMdmDefined(location.BuildingId, location.buildingId)),
        raw: location
    };
}

function isMissingGeoAddress(value) {
    const text = normalizeMdmValue(value).toLowerCase();
    return !text || text === "unable to fetch the address." || text === "null" || text === "undefined";
}

async function getMdmAssetByDeviceNameForGeo(pool, deviceName) {
    const name = normalizeMdmValue(deviceName);
    if (!name) return null;

    const result = await pool.request()
        .input("DeviceName", sql.VarChar(255), name)
        .query(`
            SELECT TOP 1 *
            FROM TSMDM_ASSET
            WHERE DeviceName = @DeviceName
               OR RealDeviceName = @DeviceName
               OR Hostname = @DeviceName
               OR LastLoggedInUser = @DeviceName
            ORDER BY LastTimeStamp DESC, DeviceTimeStamp DESC;
        `);

    return result.recordset?.[0] || null;
}


async function resolveSureMdmDeviceForGeoByName(deviceName) {
    const searchValue = normalizeMdmValue(deviceName);
    if (!searchValue) return null;

    try {
        const searchResult = await searchSureMdmDeviceByName(searchValue, 20);
        const selectedDevice = searchResult.device || {};
        const deviceID = normalizeMdmValue(firstMdmDefined(
            selectedDevice.DeviceID,
            selectedDevice.deviceID,
            selectedDevice.DeviceId,
            selectedDevice.id
        ));

        if (!deviceID) return null;

        return {
            DeviceID: deviceID,
            DeviceName: normalizeMdmValue(firstMdmDefined(
                selectedDevice.DeviceName,
                selectedDevice.deviceName,
                selectedDevice.RealDeviceName,
                selectedDevice.Hostname,
                searchValue
            )),
            PlatformType: normalizeMdmValue(firstMdmDefined(selectedDevice.PlatformType, selectedDevice.platformType)),
            source: "suremdm-device-search",
            sureMdmSearchRaw: searchResult.raw,
            selectedSureMdmDevice: selectedDevice
        };
    } catch (err) {
        console.warn("Geolocation SureMDM DeviceName lookup failed:", getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err)));
        return null;
    }
}

async function getExistingGeoAddress(pool, latitude, longitude) {
    const lat3 = roundGeo(latitude, 3);
    const lon3 = roundGeo(longitude, 3);
    if (lat3 === null || lon3 === null) return "";

    const result = await pool.request()
        .input("Latitude", sql.Float, lat3)
        .input("Longitude", sql.Float, lon3)
        .query(`
            SELECT TOP 1 LocationName
            FROM TSMDM_GEOLOCATION
            WHERE LocationName IS NOT NULL
              AND LocationName <> ''
              AND LocationName <> 'Unable to fetch the address.'
              AND ROUND(TRY_CAST(Latitude AS float), 3) = @Latitude
              AND ROUND(TRY_CAST(Longitude AS float), 3) = @Longitude
            ORDER BY [Time] DESC;
        `);

    return normalizeMdmValue(result.recordset?.[0]?.LocationName);
}

function getReverseGeocodeApiKey() {
    return normalizeMdmValue(process.env.REVERSE_GEOCODE_API_KEY);
}

function getReverseGeocodeUrl() {
    return normalizeMdmValue(process.env.REVERSE_GEOCODE_URL, "http://localhost:8081/reversegeo/api/reverse");
}

function getReverseGeocodeTimeoutMs() {
    return getGeoEnvInt("REVERSE_GEOCODE_TIMEOUT", 15000, 1000, 60000);
}

function normalizeReverseGeocodeAddress(payload) {
    return normalizeMdmValue(firstMdmDefined(
        payload?.display_name,
        payload?.displayName,
        payload?.address?.road,
        payload?.address?.commercial,
        payload?.address?.suburb,
        payload?.address?.city,
        payload?.address?.state,
        payload?.address?.country
    ));
}

async function reverseGeocodeLocation(latitude, longitude) {
    const apiKey = getReverseGeocodeApiKey();
    if (!apiKey) return "";

    const lat = normalizeMdmValue(latitude);
    const lon = normalizeMdmValue(longitude);
    if (!lat || !lon) return "";

    const response = await axios.get(getReverseGeocodeUrl(), {
        timeout: getReverseGeocodeTimeoutMs(),
        params: {
            key: apiKey,
            lat,
            lon,
            format: "json"
        }
    });

    return normalizeReverseGeocodeAddress(response.data);
}

async function updateMissingGeoAddressByCoordinate(pool, latitude, longitude, locationName) {
    const lat3 = roundGeo(latitude, 3);
    const lon3 = roundGeo(longitude, 3);
    const address = normalizeMdmValue(locationName);
    if (lat3 === null || lon3 === null || !address) return 0;

    const result = await pool.request()
        .input("Latitude", sql.Float, lat3)
        .input("Longitude", sql.Float, lon3)
        .input("LocationName", sql.VarChar(1000), address)
        .query(`
            UPDATE TSMDM_GEOLOCATION
            SET LocationName = @LocationName
            WHERE (LocationName IS NULL OR LocationName = '' OR LocationName = 'Unable to fetch the address.')
              AND ROUND(TRY_CAST(Latitude AS float), 3) = @Latitude
              AND ROUND(TRY_CAST(Longitude AS float), 3) = @Longitude;

            SELECT @@ROWCOUNT AS affectedRows;
        `);

    return result.recordset?.[0]?.affectedRows || 0;
}

async function enrichGeoAddress(pool, row) {
    if (!isMissingGeoAddress(row.LocationName)) return row.LocationName;

    const existing = await getExistingGeoAddress(pool, row.Latitude, row.Longitude);
    if (existing) return existing;

    try {
        const reversed = await reverseGeocodeLocation(row.Latitude, row.Longitude);
        return reversed || "Unable to fetch the address.";
    } catch (err) {
        console.warn("Reverse geocode failed:", err.response?.data || err.message || err);
        return "Unable to fetch the address.";
    }
}

async function insertMdmGeolocationRow(pool, row, options = {}) {
    const deviceID = normalizeMdmValue(row.DeviceID);
    const latitude = normalizeMdmValue(row.Latitude);
    const longitude = normalizeMdmValue(row.Longitude);
    const time = parseGeoDate(row.Time, new Date());

    if (!deviceID || !latitude || !longitude || !time) {
        return { inserted: 0, skipped: true, reason: "Missing DeviceID, Latitude, Longitude, or Time." };
    }

    const reverseEnabled = parseMdmBoolean(options.reverseGeocode, true);
    const locationName = reverseEnabled
        ? await enrichGeoAddress(pool, row)
        : normalizeMdmValue(row.LocationName, "Unable to fetch the address.");

    const result = await pool.request()
        .input("DeviceID", sql.VarChar(255), deviceID)
        .input("Latitude", sql.VarChar(255), latitude)
        .input("Longitude", sql.VarChar(255), longitude)
        .input("Time", sql.DateTime, time)
        .input("FloorNo", sql.VarChar(255), normalizeMdmValue(row.FloorNo))
        .input("ILTDeviceBatteryPercent", sql.VarChar(255), normalizeMdmValue(row.ILTDeviceBatteryPercent))
        .input("ILTWifiSignalStrength", sql.VarChar(255), normalizeMdmValue(row.ILTWifiSignalStrength))
        .input("ILTWifiSSID", sql.VarChar(255), normalizeMdmValue(row.ILTWifiSSID))
        .input("IsIndoor", sql.VarChar(255), normalizeMdmValue(row.IsIndoor))
        .input("LocationName", sql.VarChar(1000), locationName)
        .input("LocationMode", sql.VarChar(255), normalizeMdmValue(row.LocationMode))
        .input("IndoorLocationSource", sql.VarChar(255), normalizeMdmValue(row.IndoorLocationSource))
        .input("LocationAccuracy", sql.VarChar(255), normalizeMdmValue(row.LocationAccuracy))
        .input("BuildingId", sql.VarChar(255), normalizeMdmValue(row.BuildingId))
        .query(`
            IF NOT EXISTS (
                SELECT 1 FROM TSMDM_GEOLOCATION
                WHERE DeviceID = @DeviceID AND [Time] = @Time
            )
            BEGIN
                INSERT INTO TSMDM_GEOLOCATION
                (
                    DeviceID, Latitude, Longitude, [Time], FloorNo,
                    ILTDeviceBatteryPercent, ILTWifiSignalStrength, ILTWifiSSID,
                    IsIndoor, LocationName, LocationMode, IndoorLocationSource,
                    LocationAccuracy, BuildingId
                )
                VALUES
                (
                    @DeviceID, @Latitude, @Longitude, @Time, @FloorNo,
                    @ILTDeviceBatteryPercent, @ILTWifiSignalStrength, @ILTWifiSSID,
                    @IsIndoor, @LocationName, @LocationMode, @IndoorLocationSource,
                    @LocationAccuracy, @BuildingId
                );
            END

            SELECT @@ROWCOUNT AS affectedRows;
        `);

    if (!isMissingGeoAddress(locationName)) {
        await updateMissingGeoAddressByCoordinate(pool, latitude, longitude, locationName);
    }

    return {
        inserted: result.recordset?.[0]?.affectedRows || 0,
        DeviceID: deviceID,
        Latitude: latitude,
        Longitude: longitude,
        Time: time,
        LocationName: locationName
    };
}

function normalizeGeoDbRow(row) {
    const longitude = firstMdmDefined(row.Longitude, row.longitude, "");
    const latitude = firstMdmDefined(row.Latitude, row.latitude, "");
    const locationName = normalizeMdmValue(firstMdmDefined(row.LocationName, row.Address, row.address));
    const deviceName = normalizeMdmValue(firstMdmDefined(row.DeviceName, row.ComputerName, row.Object_Client_Name));
    const username = normalizeMdmValue(firstMdmDefined(row.LastLoggedInUser, row.Object_Client_Name, row.DeviceName, row.ComputerName));
    const model = normalizeMdmValue(firstMdmDefined(row.DeviceModelName, row.Model));
    const serialNumber = normalizeMdmValue(firstMdmDefined(row.SerialNumber, row.BiosSerialkey));

    return {
        ...row,
        DeviceID: normalizeMdmValue(row.DeviceID),
        DeviceName: deviceName,
        Username: username,
        LastLoggedInUser: username,
        Model: model,
        DeviceModelName: model,
        SerialNumber: serialNumber,
        BiosSerialkey: serialNumber,
        Address: locationName,
        LocationName: locationName,
        Longitude: longitude !== undefined && longitude !== null ? String(longitude) : "",
        Latitude: latitude !== undefined && latitude !== null ? String(latitude) : "",
        LongitudeLatitude: `${longitude} / ${latitude}`,
        longitudeLatitude: `${longitude} / ${latitude}`,
        Time: row.Time,
        DateTime: row.Time
    };
}

async function getGeolocationRowsByDeviceID(pool, deviceID, mode = "All") {
    const queryMode = normalizeMdmValue(mode, "All").toLowerCase();
    const device = normalizeMdmValue(deviceID);
    if (!device) throw new Error("DeviceID is required.");

    const result = await pool.request()
        .input("DeviceID", sql.VarChar(255), device)
        .query(`
            ;WITH geo AS (
                SELECT g.*
                FROM TSMDM_GEOLOCATION g
                WHERE g.DeviceID = @DeviceID
            )
            SELECT ${queryMode === "live" ? "TOP 1" : ""}
                g.*,
                a.DeviceName,
                CASE WHEN a.LastLoggedInUser IS NOT NULL AND a.LastLoggedInUser <> ''
                     THEN a.LastLoggedInUser ELSE a.DeviceName END AS LastLoggedInUser,
                a.DeviceModelName,
                a.SerialNumber,
                a.PlatformType,
                o.Object_Root_Idn,
                o.Object_Client_Name,
                o.Model,
                ci.BiosSerialkey
            FROM geo g
            LEFT JOIN TSMDM_ASSET a
                ON a.DeviceID = g.DeviceID
            LEFT JOIN TSMDM_TS_OBJECT_MAPPING map
                ON map.MDM_Asset_Idn = a.MDM_Asset_Idn
            LEFT JOIN TS_OBJECT_ROOT o
                ON o.Object_Root_Idn = map.Object_Root_Idn
            LEFT JOIN TS_CLIENT_INFO ci
                ON ci.Object_Root_Idn = o.Object_Root_Idn
            ORDER BY g.[Time] DESC;
        `);

    return result.recordset.map(normalizeGeoDbRow);
}

async function getLiveGeolocationAll(pool, deviceID = "") {
    const result = await pool.request()
        .input("DeviceID", sql.VarChar(255), normalizeMdmValue(deviceID))
        .query(`
            ;WITH latest AS (
                SELECT DeviceID, MAX([Time]) AS MaxTime
                FROM TSMDM_GEOLOCATION
                GROUP BY DeviceID
            )
            SELECT
                g.*,
                a.DeviceName,
                CASE WHEN a.LastLoggedInUser IS NOT NULL AND a.LastLoggedInUser <> ''
                     THEN a.LastLoggedInUser ELSE a.DeviceName END AS LastLoggedInUser,
                a.DeviceModelName,
                a.SerialNumber,
                a.PlatformType,
                o.Object_Root_Idn,
                o.Object_Client_Name,
                o.Model,
                ci.BiosSerialkey
            FROM latest l
            INNER JOIN TSMDM_GEOLOCATION g
                ON g.DeviceID = l.DeviceID AND g.[Time] = l.MaxTime
            LEFT JOIN TSMDM_ASSET a
                ON a.DeviceID = g.DeviceID
            LEFT JOIN TSMDM_TS_OBJECT_MAPPING map
                ON map.MDM_Asset_Idn = a.MDM_Asset_Idn
            LEFT JOIN TS_OBJECT_ROOT o
                ON o.Object_Root_Idn = map.Object_Root_Idn
            LEFT JOIN TS_CLIENT_INFO ci
                ON ci.Object_Root_Idn = o.Object_Root_Idn
            WHERE (@DeviceID = '' OR g.DeviceID = @DeviceID)
            ORDER BY g.[Time] DESC;
        `);

    return result.recordset.map(normalizeGeoDbRow);
}

async function fetchSureMdmLastLocation(deviceID) {
    const response = await callSureMdmApi("v2/location", {
        method: "POST",
        contentType: "application/json",
        data: { DeviceID: normalizeMdmValue(deviceID) }
    });

    return response.data;
}

async function fetchSureMdmLocationHistory(deviceID, startTime, endTime) {
    const from = encodeURIComponent(normalizeMdmValue(startTime, startOfCurrentYearForSureMdm()));
    const to = encodeURIComponent(normalizeMdmValue(endTime, formatGeoDateForSureMdm(new Date())));
    const device = encodeURIComponent(normalizeMdmValue(deviceID));

    const response = await callSureMdmApi(`v2/location?FromTime=${from}&ToTime=${to}&DeviceID=${device}`, {
        method: "GET",
        contentType: ""
    });

    return response.data;
}

async function syncSureMdmGeolocation(pool, deviceID, options = {}) {
    const mode = normalizeMdmValue(options.mode, "Live").toLowerCase();
    const asset = options.asset || await getMdmAssetByDeviceID(pool, deviceID) || { DeviceID: deviceID };
    const raw = mode === "all" || mode === "history"
        ? await fetchSureMdmLocationHistory(deviceID, options.startTime, options.endTime)
        : await fetchSureMdmLastLocation(deviceID);

    const locations = extractSureMdmLocations(raw);
    const saved = [];

    for (const location of locations) {
        const row = normalizeGeoLocationRow(location, asset);
        if (!row.DeviceID) row.DeviceID = normalizeMdmValue(deviceID);
        saved.push(await insertMdmGeolocationRow(pool, row, {
            reverseGeocode: options.reverseGeocode !== false
        }));
    }

    return {
        DeviceID: normalizeMdmValue(deviceID),
        raw,
        received: locations.length,
        saved
    };
}

async function resolveGeolocationTargetByRequest(pool, body = {}) {
    const objectAgent = normalizeMdmValue(firstMdmDefined(
        body.objectAgent,
        body.Object_Agent,
        body.agent
    ), "EM").toUpperCase();

    const objectRootIdn = parseMdmInt(firstMdmDefined(
        body.Object_Root_Idn,
        body.objectRootIdn,
        body.objectRootID,
        objectAgent === "EM" ? body.assetId : undefined
    ), 0);

    const mdmAssetIdn = parseMdmInt(firstMdmDefined(
        body.MDM_Asset_Idn,
        body.mdmAssetIdn,
        body.mdmAssetID,
        objectAgent === "MDM" ? body.assetId : undefined
    ), 0);

    // MDM/SureMDM DeviceID only. Do NOT treat Object_DeviceID as DeviceID for EM assets,
    // because TS_OBJECT_ROOT.Object_DeviceID is not the same key as TSMDM_ASSET.DeviceID.
    const requestedMdmDeviceID = normalizeMdmValue(firstMdmDefined(
        body.MDM_DeviceID,
        body.mdmDeviceID,
        body.mdmDeviceId,
        body.DeviceID,
        body.deviceID,
        body.deviceId
    ));

    const requestedObjectDeviceID = normalizeMdmValue(firstMdmDefined(
        body.Object_DeviceID,
        body.objectDeviceID,
        body.objectDeviceId
    ));

    const requestedDeviceName = normalizeMdmValue(firstMdmDefined(
        body.DeviceName,
        body.deviceName,
        body.ComputerName,
        body.computerName
    ));

    let asset = null;

    // For EM/Windows rows, Object_Root_Idn is the strongest source. Resolve it through
    // TSMDM_TS_OBJECT_MAPPING -> TSMDM_ASSET before considering any DeviceID from payload.
    if (objectRootIdn) {
        asset = await getMdmAssetByObjectRoot(pool, objectRootIdn, { syncMapping: true });
    }

    if (!asset && mdmAssetIdn) {
        asset = await getMdmAssetByMdmAssetId(pool, mdmAssetIdn);
    }

    if (!asset && requestedMdmDeviceID) {
        asset = await getMdmAssetByDeviceID(pool, requestedMdmDeviceID);
    }

    // For pure MDM rows, Object_DeviceID is actually TSMDM_ASSET.DeviceID in the asset-list API.
    // For EM rows, Object_DeviceID belongs to TS_OBJECT_ROOT and must not be used as MDM DeviceID.
    if (!asset && objectAgent === "MDM" && requestedObjectDeviceID) {
        asset = await getMdmAssetByDeviceID(pool, requestedObjectDeviceID);
    }

    if (!asset && requestedDeviceName) {
        asset = await getMdmAssetByDeviceNameForGeo(pool, requestedDeviceName);
    }

    let sureMdmNameLookup = null;
    if ((!asset || !normalizeMdmValue(asset.DeviceID)) && requestedDeviceName) {
        sureMdmNameLookup = await resolveSureMdmDeviceForGeoByName(requestedDeviceName);
        if (sureMdmNameLookup?.DeviceID) {
            asset = {
                ...(asset || {}),
                ...sureMdmNameLookup,
                Object_Root_Idn: objectRootIdn || asset?.Object_Root_Idn || 0,
                EM_Object_DeviceID: requestedObjectDeviceID || asset?.EM_Object_DeviceID || "",
                MDM_Asset_Idn: mdmAssetIdn || asset?.MDM_Asset_Idn || 0
            };
        }
    }

    let deviceID = normalizeMdmValue(asset?.DeviceID);

    // Only trust raw payload DeviceID without a TSMDM_ASSET match when this is an MDM row
    // or when no EM Object_Root_Idn was supplied. This prevents EM Object_DeviceID from
    // accidentally being used against TSMDM_GEOLOCATION.DeviceID.
    if (!deviceID && requestedMdmDeviceID && (objectAgent === "MDM" || !objectRootIdn)) {
        deviceID = requestedMdmDeviceID;
    }

    if (!deviceID && objectAgent === "MDM" && requestedObjectDeviceID) {
        deviceID = requestedObjectDeviceID;
    }

    if (!deviceID) {
        throw new Error(
            requestedDeviceName
                ? `Could not resolve SureMDM DeviceID for geolocation from DeviceName '${requestedDeviceName}'. Check TSMDM_TS_OBJECT_MAPPING / TSMDM_ASSET, or send MDM_DeviceID from TSMDM_ASSET.DeviceID.`
                : "Could not resolve SureMDM DeviceID for geolocation."
        );
    }

    return {
        Object_Root_Idn: objectRootIdn || asset?.Object_Root_Idn || 0,
        Object_DeviceID: requestedObjectDeviceID,
        MDM_Asset_Idn: mdmAssetIdn || asset?.MDM_Asset_Idn || 0,
        DeviceID: deviceID,
        asset,
        sureMdmNameLookup
    };
}

function shouldSyncGeolocation(req) {
    const body = req.body || {};
    return parseMdmBoolean(firstMdmDefined(
        body.Sync,
        body.sync,
        body.Refresh,
        body.refresh,
        req.query?.sync,
        req.query?.refresh
    ), false);
}

async function getMdmAssetsForGeolocationSync(pool, options = {}) {
    const limit = parseMdmInt(options.limit, getGeoEnvInt("GEO_SYNC_DEVICE_LIMIT", 0, 0));
    const onlyTrackingOn = parseMdmBoolean(options.onlyTrackingOn, getGeoEnvBoolean("GEO_SYNC_ONLY_TRACKING_ON", false));
    const skipLinux = parseMdmBoolean(options.skipLinux, getGeoEnvBoolean("GEO_SYNC_SKIP_LINUX", true));
    const specificDeviceID = normalizeMdmValue(options.deviceID);

    const result = await pool.request()
        .input("Limit", sql.Int, limit)
        .input("OnlyTrackingOn", sql.Bit, onlyTrackingOn)
        .input("SkipLinux", sql.Bit, skipLinux)
        .input("DeviceID", sql.VarChar(255), specificDeviceID)
        .query(`
            SELECT ${limit > 0 ? "TOP (@Limit)" : ""}
                MDM_Asset_Idn,
                DeviceID,
                DeviceName,
                PlatformType,
                TrackingOn,
                ConnectionStatus,
                LastTimeStamp,
                DeviceTimeStamp,
                LastLoggedInUser,
                DeviceModelName,
                SerialNumber
            FROM TSMDM_ASSET
            WHERE DeviceID IS NOT NULL
              AND DeviceID <> ''
              AND (@DeviceID = '' OR DeviceID = @DeviceID)
              AND (@OnlyTrackingOn = 0 OR ISNULL(TrackingOn, 0) = 1)
              AND (@SkipLinux = 0 OR ISNULL(PlatformType, '') <> 'Linux')
            ORDER BY ISNULL(LastTimeStamp, DeviceTimeStamp) DESC, DeviceName ASC;
        `);

    return result.recordset || [];
}

async function runGeoWithConcurrency(items, concurrency, worker) {
    const results = [];
    const safeConcurrency = Math.max(1, Math.min(parseMdmInt(concurrency, 1), items.length || 1));
    let index = 0;

    const runners = Array.from({ length: safeConcurrency }, async () => {
        while (index < items.length) {
            const currentIndex = index++;
            try {
                results[currentIndex] = await worker(items[currentIndex], currentIndex);
            } catch (err) {
                results[currentIndex] = {
                    success: false,
                    errorMessage: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err)),
                    rawError: err.response?.data || undefined
                };
            }
        }
    });

    await Promise.all(runners);
    return results;
}

async function syncAllSureMdmGeolocation(options = {}) {
    const pool = await getSqlPoolWithRetry();
    const mode = normalizeMdmValue(options.mode, process.env.GEO_SYNC_MODE || "Live");
    const concurrency = parseMdmInt(options.concurrency, getGeoEnvInt("GEO_SYNC_CONCURRENCY", 5, 1, 25));
    const reverseOnInsert = parseMdmBoolean(options.reverseGeocode, false);
    const startTime = firstMdmDefined(options.startTime, process.env.GEO_SYNC_START_TIME);
    const endTime = firstMdmDefined(options.endTime, process.env.GEO_SYNC_END_TIME);
    const assets = await getMdmAssetsForGeolocationSync(pool, options);

    const startedAt = new Date();
    let successCount = 0;
    let errorCount = 0;
    let receivedCount = 0;
    let insertedCount = 0;

    const data = await runGeoWithConcurrency(assets, concurrency, async asset => {
        const result = await syncSureMdmGeolocation(pool, asset.DeviceID, {
            mode,
            asset,
            startTime,
            endTime,
            reverseGeocode: reverseOnInsert
        });

        const inserted = (result.saved || []).reduce((sum, row) => sum + Number(row.inserted || 0), 0);
        successCount += 1;
        receivedCount += result.received || 0;
        insertedCount += inserted;

        return {
            success: true,
            DeviceID: asset.DeviceID,
            DeviceName: asset.DeviceName,
            PlatformType: asset.PlatformType,
            received: result.received,
            inserted
        };
    });

    errorCount = data.filter(item => item && item.success === false).length;

    return {
        startedAt,
        endedAt: new Date(),
        mode,
        totalDevices: assets.length,
        successCount,
        errorCount,
        receivedCount,
        insertedCount,
        concurrency,
        reverseOnInsert,
        data
    };
}

async function getDistinctMissingGeoCoordinates(pool, limit = 100) {
    const safeLimit = Math.max(1, Math.min(parseMdmInt(limit, 100), 1000));

    const result = await pool.request()
        .input("Limit", sql.Int, safeLimit)
        .query(`
            ;WITH missing AS (
                SELECT
                    ROUND(TRY_CAST(Latitude AS float), 3) AS Latitude3,
                    ROUND(TRY_CAST(Longitude AS float), 3) AS Longitude3,
                    MAX([Time]) AS LatestTime,
                    COUNT(1) AS MissingRows
                FROM TSMDM_GEOLOCATION
                WHERE (LocationName IS NULL OR LocationName = '' OR LocationName = 'Unable to fetch the address.')
                  AND TRY_CAST(Latitude AS float) IS NOT NULL
                  AND TRY_CAST(Longitude AS float) IS NOT NULL
                GROUP BY ROUND(TRY_CAST(Latitude AS float), 3), ROUND(TRY_CAST(Longitude AS float), 3)
            )
            SELECT TOP (@Limit)
                Latitude3 AS Latitude,
                Longitude3 AS Longitude,
                MissingRows,
                LatestTime
            FROM missing
            ORDER BY LatestTime DESC;
        `);

    return result.recordset || [];
}

async function reverseGeocodeSingleCoordinate(options = {}) {
    const pool = await getSqlPoolWithRetry();
    const latitude = normalizeMdmValue(firstMdmDefined(options.latitude, options.Latitude, options.lat));
    const longitude = normalizeMdmValue(firstMdmDefined(options.longitude, options.Longitude, options.lon, options.lng));
    const startedAt = new Date();

    if (!latitude || !longitude) {
        throw new Error("Latitude and Longitude are required.");
    }

    if (!getReverseGeocodeApiKey()) {
        throw new Error("REVERSE_GEOCODE_API_KEY is not configured.");
    }

    const address = await reverseGeocodeLocation(latitude, longitude) || "Unable to fetch the address.";
    const updatedRows = isMissingGeoAddress(address)
        ? 0
        : await updateMissingGeoAddressByCoordinate(pool, latitude, longitude, address);

    return {
        startedAt,
        endedAt: new Date(),
        Latitude: latitude,
        Longitude: longitude,
        LocationName: address,
        address,
        updatedRows,
        storedInDatabase: updatedRows > 0,
        source: "nominatim-java-gateway"
    };
}

async function backfillMissingGeoAddresses(options = {}) {
    const pool = await getSqlPoolWithRetry();
    const limit = parseMdmInt(options.limit, getGeoEnvInt("GEO_REVERSE_GEOCODE_BATCH_SIZE", 50, 1, 1000));
    const delayMs = parseMdmInt(options.delayMs, getGeoEnvInt("GEO_REVERSE_GEOCODE_DELAY_MS", 1200, 0, 60000));
    const coordinates = await getDistinctMissingGeoCoordinates(pool, limit);
    const startedAt = new Date();

    const results = [];
    let updatedRows = 0;
    let apiCalls = 0;
    let reusedExisting = 0;
    let failedCount = 0;

    for (const coordinate of coordinates) {
        const latitude = coordinate.Latitude;
        const longitude = coordinate.Longitude;
        const missingRows = coordinate.MissingRows || 0;

        try {
            let address = await getExistingGeoAddress(pool, latitude, longitude);
            const usedExistingAddress = Boolean(address);

            if (usedExistingAddress) {
                reusedExisting += 1;
            } else {
                if (!getReverseGeocodeApiKey()) {
                    results.push({
                        Latitude: latitude,
                        Longitude: longitude,
                        MissingRows: missingRows,
                        LocationName: "",
                        address: "",
                        updatedRows: 0,
                        storedInDatabase: false,
                        skipped: true,
                        reason: "REVERSE_GEOCODE_API_KEY is not configured."
                    });
                    continue;
                }

                if (apiCalls > 0 && delayMs > 0) await sleepGeo(delayMs);
                address = await reverseGeocodeLocation(latitude, longitude);
                apiCalls += 1;
            }

            if (!address) address = "Unable to fetch the address.";
            const affectedRows = isMissingGeoAddress(address)
                ? 0
                : await updateMissingGeoAddressByCoordinate(pool, latitude, longitude, address);

            updatedRows += affectedRows;
            results.push({
                Latitude: latitude,
                Longitude: longitude,
                MissingRows: missingRows,
                LocationName: address,
                address,
                updatedRows: affectedRows,
                storedInDatabase: affectedRows > 0,
                source: usedExistingAddress ? "existing-db-address" : "nominatim-java-gateway"
            });
        } catch (err) {
            failedCount += 1;
            results.push({
                Latitude: latitude,
                Longitude: longitude,
                MissingRows: missingRows,
                LocationName: "",
                address: "",
                updatedRows: 0,
                storedInDatabase: false,
                errorMessage: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err))
            });
        }
    }

    return {
        startedAt,
        endedAt: new Date(),
        totalCoordinates: coordinates.length,
        updatedRows,
        apiCalls,
        reusedExisting,
        failedCount,
        results
    };
}

async function handleGetMdmGeolocation(req, res) {
    try {
        const queryType = normalizeMdmValue(firstMdmDefined(req.body?.QueryType, req.body?.queryType), "All");
        const mode = queryType.toLowerCase() === "live" ? "Live" : "All";
        const pool = await getSqlPoolWithRetry();
        const target = await resolveGeolocationTargetByRequest(pool, req.body || {});

        let sync = null;
        if (shouldSyncGeolocation(req)) {
            sync = await syncSureMdmGeolocation(pool, target.DeviceID, {
                mode,
                asset: target.asset,
                startTime: firstMdmDefined(req.body?.StartTime, req.body?.startTime),
                endTime: firstMdmDefined(req.body?.EndTime, req.body?.endTime),
                reverseGeocode: true
            });
        }

        const data = await getGeolocationRowsByDeviceID(pool, target.DeviceID, mode);

        return res.json({
            success: true,
            status: 1,
            message: "success",
            totalRecords: data.length,
            sync,
            data
        });
    } catch (err) {
        const responseData = err.response?.data || err.responseData;
        return res.status(500).json({
            success: false,
            status: 0,
            message: "Failed to retrieve MDM geolocation.",
            errorMessage: getMdmErrorMessage(responseData, err.message || String(err)),
            data: []
        });
    }
}

app.post("/api/mdm/GetMDMGeolocation", authenticateToken, handleGetMdmGeolocation);
app.post("/api/mdm/GetMDMGeolocationNonWindows", authenticateToken, handleGetMdmGeolocation);

app.post("/api/mdm/GetMDMGeolocationLiveAll", authenticateToken, async (req, res) => {
    try {
        const pool = await getSqlPoolWithRetry();
        const deviceID = normalizeMdmValue(firstMdmDefined(req.body?.DeviceID, req.body?.deviceID, req.query?.DeviceID, req.query?.deviceID));
        const data = await getLiveGeolocationAll(pool, deviceID);

        return res.json({
            success: true,
            status: 1,
            message: "success",
            totalRecords: data.length,
            data
        });
    } catch (err) {
        return res.status(500).json({
            success: false,
            status: 0,
            message: "Failed to retrieve live MDM geolocation.",
            errorMessage: err.message || String(err),
            data: []
        });
    }
});

app.post("/api/geolocation/sync", authenticateToken, async (req, res) => {
    try {
        const mode = normalizeMdmValue(firstMdmDefined(req.body?.mode, req.body?.QueryType), "Live");
        const pool = await getSqlPoolWithRetry();
        const target = await resolveGeolocationTargetByRequest(pool, req.body || {});
        const sync = await syncSureMdmGeolocation(pool, target.DeviceID, {
            mode,
            asset: target.asset,
            startTime: firstMdmDefined(req.body?.StartTime, req.body?.startTime),
            endTime: firstMdmDefined(req.body?.EndTime, req.body?.endTime),
            reverseGeocode: true
        });

        return res.json({ success: true, message: "Geolocation synchronized.", data: sync });
    } catch (err) {
        return res.status(500).json({
            success: false,
            message: "Failed to synchronize geolocation.",
            errorMessage: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err))
        });
    }
});

app.post("/api/geolocation/sync-all", authenticateToken, async (req, res) => {
    try {
        const data = await syncAllSureMdmGeolocation({
            mode: firstMdmDefined(req.body?.mode, req.body?.QueryType, "Live"),
            startTime: firstMdmDefined(req.body?.StartTime, req.body?.startTime),
            endTime: firstMdmDefined(req.body?.EndTime, req.body?.endTime),
            concurrency: firstMdmDefined(req.body?.concurrency, req.body?.Concurrency),
            limit: firstMdmDefined(req.body?.limit, req.body?.Limit),
            onlyTrackingOn: firstMdmDefined(req.body?.onlyTrackingOn, req.body?.OnlyTrackingOn),
            skipLinux: firstMdmDefined(req.body?.skipLinux, req.body?.SkipLinux),
            reverseGeocode: parseMdmBoolean(firstMdmDefined(req.body?.reverseGeocode, req.body?.ReverseGeocode), false)
        });

        return res.json({ success: true, message: "All-device geolocation sync completed.", data });
    } catch (err) {
        return res.status(500).json({
            success: false,
            message: "Failed to synchronize all geolocations.",
            errorMessage: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err))
        });
    }
});

app.post("/api/geolocation/reverse-geocode", authenticateToken, async (req, res) => {
    try {
        const latitude = firstMdmDefined(req.body?.latitude, req.body?.Latitude, req.body?.lat);
        const longitude = firstMdmDefined(req.body?.longitude, req.body?.Longitude, req.body?.lon, req.body?.lng);

        if (latitude !== undefined && longitude !== undefined) {
            const data = await reverseGeocodeSingleCoordinate({ latitude, longitude });
            return res.json({ success: true, message: "Reverse geocode completed.", data });
        }

        const data = await backfillMissingGeoAddresses({
            limit: firstMdmDefined(req.body?.limit, req.body?.Limit),
            delayMs: firstMdmDefined(req.body?.delayMs, req.body?.DelayMs)
        });

        return res.json({ success: true, message: "Reverse geocode backfill completed.", data });
    } catch (err) {
        return res.status(500).json({
            success: false,
            message: "Failed to reverse geocode geolocation address.",
            errorMessage: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err))
        });
    }
});

