/*
|--------------------------------------------------------------------------
| Java-style Scheduled Geolocation Debug Jobs
|--------------------------------------------------------------------------
| Mirrors ApiMdmController behavior:
| - scheduled backend run at interval/fixed delay
| - manual API returns full debug result object
| - console can print the same result for troubleshooting
|--------------------------------------------------------------------------
*/

const geoWorkerState = {
    scheduledGeolocation: {
        enabled: false,
        running: false,
        intervalMs: null,
        lastStartedAt: null,
        lastFinishedAt: null,
        lastResult: null,
        lastError: null
    },
    reverseGeocode: {
        running: false,
        lastStartedAt: null,
        lastFinishedAt: null,
        lastResult: null,
        lastError: null
    }
};

function geoNowString() {
    return new Date().toISOString().replace("T", " ").replace("Z", " UTC");
}

function geoRunId() {
    return Math.floor(Math.random() * 100000);
}

function geoIncludeDeviceResults() {
    return getGeoEnvBoolean("GEO_DEBUG_INCLUDE_DEVICE_RESULTS", true);
}

function geoDebugLogEnabled() {
    return getGeoEnvBoolean("GEO_DEBUG_LOG_RESULT", true);
}

function logGeoDebugResult(label, result) {
    if (!geoDebugLogEnabled()) return;
    try {
        console.log(`${label}: ${JSON.stringify(result, null, 2)}`);
    } catch (err) {
        console.log(`${label}:`, result);
    }
}

function getGeoIntervalRange(intervalHours = 1) {
    const safeHours = Math.max(parseMdmInt(intervalHours, 1), 1);
    const end = new Date();
    const start = new Date(end.getTime() - safeHours * 60 * 60 * 1000);

    return {
        startTime: formatGeoDateForSureMdm(start),
        endTime: formatGeoDateForSureMdm(end)
    };
}

function mapSyncResultToJavaShape(syncResult, includeDetails = true) {
    const data = Array.isArray(syncResult?.data) ? syncResult.data : [];

    return {
        action: "Logging MDM Geolocations",
        mode: syncResult?.mode || "",
        startTime: syncResult?.startedAt || null,
        endTime: syncResult?.endedAt || null,
        totalAssets: syncResult?.totalDevices || 0,
        totalQueued: data.length,
        totalSuccess: syncResult?.successCount || 0,
        totalFail: syncResult?.errorCount || 0,
        totalReceivedLocations: syncResult?.receivedCount || 0,
        totalInserted: syncResult?.insertedCount || 0,
        concurrency: syncResult?.concurrency || 0,
        reverseOnInsert: Boolean(syncResult?.reverseOnInsert),
        status: (syncResult?.errorCount || 0) === 0 ? 1 : 0,
        message: (syncResult?.errorCount || 0) === 0 ? "Success" : "Completed with errors",
        results: includeDetails ? data : undefined
    };
}

function mapReverseResultToJavaShape(reverseResult, includeDetails = true) {
    return {
        action: "Reverse Geocode MDM Geolocation Addresses",
        startTime: reverseResult?.startedAt || null,
        endTime: reverseResult?.endedAt || null,
        totalCoordinates: reverseResult?.totalCoordinates || 0,
        data_updateExisting: reverseResult?.reusedExisting || 0,
        data_reverseGeocode: reverseResult?.updatedRows || 0,
        apiCalls: reverseResult?.apiCalls || 0,
        failedCount: reverseResult?.failedCount || 0,
        status: (reverseResult?.failedCount || 0) === 0 ? 1 : 0,
        message: (reverseResult?.failedCount || 0) === 0 ? "Success" : "Completed with errors",
        results: includeDetails ? (reverseResult?.results || []) : undefined
    };
}

async function runReverseGeocodeDebugJob(options = {}) {
    if (geoWorkerState.reverseGeocode.running) {
        return {
            action: "Reverse Geocode MDM Geolocation Addresses",
            status: 0,
            message: "Reverse geocode job is already running.",
            running: true
        };
    }

    geoWorkerState.reverseGeocode.running = true;
    geoWorkerState.reverseGeocode.lastStartedAt = new Date();
    geoWorkerState.reverseGeocode.lastError = null;

    try {
        const rawResult = await backfillMissingGeoAddresses({
            limit: firstMdmDefined(options.limit, process.env.GEO_REVERSE_GEOCODE_BATCH_SIZE),
            delayMs: firstMdmDefined(options.delayMs, process.env.GEO_REVERSE_GEOCODE_DELAY_MS)
        });
        const result = mapReverseResultToJavaShape(rawResult, options.includeDetails !== false);
        geoWorkerState.reverseGeocode.lastResult = result;
        return result;
    } catch (err) {
        const result = {
            action: "Reverse Geocode MDM Geolocation Addresses",
            status: 0,
            message: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err)),
            error: err.response?.data || undefined
        };
        geoWorkerState.reverseGeocode.lastError = result.message;
        geoWorkerState.reverseGeocode.lastResult = result;
        return result;
    } finally {
        geoWorkerState.reverseGeocode.running = false;
        geoWorkerState.reverseGeocode.lastFinishedAt = new Date();
    }
}

async function runGeolocationSyncDebugJob(options = {}) {
    const intervalHours = parseMdmInt(firstMdmDefined(
        options.intervalHours,
        process.env.GEO_CUSTOM_REPORT_INTERVAL_HOURS
    ), 1);

    const range = getGeoIntervalRange(intervalHours);
    const mode = normalizeMdmValue(firstMdmDefined(options.mode, process.env.GEO_SYNC_MODE, "Live"));
    const defaultStartTime = mode.toLowerCase() === "live" ? undefined : range.startTime;
    const defaultEndTime = mode.toLowerCase() === "live" ? undefined : range.endTime;

    const rawResult = await syncAllSureMdmGeolocation({
        mode,
        startTime: firstMdmDefined(options.startTime, defaultStartTime),
        endTime: firstMdmDefined(options.endTime, defaultEndTime),
        concurrency: firstMdmDefined(options.concurrency, process.env.GEO_SYNC_CONCURRENCY),
        limit: firstMdmDefined(options.limit, process.env.GEO_SYNC_DEVICE_LIMIT),
        onlyTrackingOn: firstMdmDefined(options.onlyTrackingOn, process.env.GEO_SYNC_ONLY_TRACKING_ON),
        skipLinux: firstMdmDefined(options.skipLinux, process.env.GEO_SYNC_SKIP_LINUX),
        reverseGeocode: parseMdmBoolean(firstMdmDefined(options.reverseGeocode, false), false)
    });

    const javaShape = mapSyncResultToJavaShape(rawResult, options.includeDetails !== false);
    javaShape.intervalHours = intervalHours;
    javaShape.queryStartTime = firstMdmDefined(options.startTime, defaultStartTime, "");
    javaShape.queryEndTime = firstMdmDefined(options.endTime, defaultEndTime, "");
    javaShape.trigger = normalizeMdmValue(options.trigger, "manual");
    return javaShape;
}


async function runUpdateAssetsGeolocation(options = {}) {
    if (geoWorkerState.scheduledGeolocation.running) {
        return {
            action: "UpdateAssetsGeolocation",
            startTime: geoNowString(),
            status: 0,
            message: "Geolocation scheduled job is already running.",
            running: true,
            lastStartedAt: geoWorkerState.scheduledGeolocation.lastStartedAt
        };
    }

    const runId = geoRunId();
    const result = {
        action: "UpdateAssetsGeolocation",
        runId,
        trigger: normalizeMdmValue(options.trigger, "manual"),
        startTime: geoNowString()
    };

    geoWorkerState.scheduledGeolocation.running = true;
    geoWorkerState.scheduledGeolocation.lastStartedAt = new Date();
    geoWorkerState.scheduledGeolocation.lastError = null;

    console.log(`EMA [${runId}] [START] UpdateAssetsGeolocation(): ${result.startTime}`);

    try {
        result.MDMGeolocation_result = await runGeolocationSyncDebugJob({
            ...options,
            mode: "Live",
            startTime: undefined,
            endTime: undefined,
            includeDetails: options.includeDetails !== false
        });
    } catch (err) {
        result.MDMGeolocation_result = {
            action: "Logging MDM Geolocations",
            mode: "Live",
            status: 0,
            message: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err))
        };
    }

    try {
        if (parseMdmBoolean(firstMdmDefined(options.skipReverseGeocode, process.env.GEO_SKIP_REVERSE_GEOCODE), false)) {
            result.MDMGeolocationAddress_result = {
                action: "Reverse Geocode MDM Geolocation Addresses",
                status: 1,
                message: "Skipped by configuration."
            };
        } else {
            result.MDMGeolocationAddress_result = await runReverseGeocodeDebugJob({
                ...options,
                includeDetails: options.includeDetails !== false
            });
        }
    } catch (err) {
        result.MDMGeolocationAddress_result = {
            action: "Reverse Geocode MDM Geolocation Addresses",
            status: 0,
            message: getMdmErrorMessage(err.response?.data || err.responseData, err.message || String(err))
        };
    }

    result.endTime = geoNowString();
    result.status = result.MDMGeolocation_result?.status === 1 && result.MDMGeolocationAddress_result?.status === 1 ? 1 : 0;
    result.message = result.status === 1 ? "Success" : "Completed with errors";

    geoWorkerState.scheduledGeolocation.lastResult = result;
    geoWorkerState.scheduledGeolocation.lastError = result.status === 1 ? null : result.message;
    geoWorkerState.scheduledGeolocation.running = false;
    geoWorkerState.scheduledGeolocation.lastFinishedAt = new Date();

    console.log(`EMA [${runId}] [END] UpdateAssetsGeolocation(): ${result.endTime}`);
    logGeoDebugResult("UpdateAssetsGeolocation", result);

    return result;
}

