function scheduleGeoFixedDelay(label, workerFn, intervalMs, initialDelayMs) {
    let stopped = false;

    const tick = async () => {
        if (stopped) return;
        try {
            await workerFn();
        } catch (err) {
            console.error(`${label} failed:`, err.response?.data || err.message || err);
        } finally {
            if (!stopped) setTimeout(tick, intervalMs);
        }
    };

    setTimeout(tick, Math.max(initialDelayMs, 0));

    return () => {
        stopped = true;
    };
}

function startGeolocationSchedulers() {
    const enabled = getGeoEnvBoolean("GEO_BACKGROUND_SYNC_ENABLED", true);
    const intervalMs = getGeoEnvInt("GEO_SYNC_INTERVAL_MS", 60 * 60 * 1000, 60 * 1000);
    const runOnStart = getGeoEnvBoolean("GEO_WORKER_RUN_ON_START", true);
    const initialDelayMs = runOnStart ? 0 : getGeoEnvInt("GEO_WORKER_INITIAL_DELAY_MS", 30 * 1000, 0);

    geoWorkerState.scheduledGeolocation.enabled = enabled;
    geoWorkerState.scheduledGeolocation.intervalMs = intervalMs;

    if (!enabled) {
        console.log("Geolocation scheduler disabled. Set GEO_BACKGROUND_SYNC_ENABLED=true to enable it.");
        return;
    }

    console.log("Geolocation scheduler enabled:", {
        intervalMs,
        runOnStart,
        initialDelayMs,
        mode: process.env.GEO_SYNC_MODE || "Live",
        deviceLimit: process.env.GEO_SYNC_DEVICE_LIMIT || "0",
        debugLogResult: geoDebugLogEnabled()
    });

    scheduleGeoFixedDelay(
        "Geolocation scheduler",
        () => runUpdateAssetsGeolocation({
            trigger: "schedule",
            includeDetails: geoIncludeDeviceResults()
        }),
        intervalMs,
        initialDelayMs
    );
}

