async function sendTaskDetailResponse(req, res) {
    try {
        const jobId = getTaskIdFromRequest(req);
        if (!jobId) return res.status(400).json({ success: false, message: "job_id is required" });

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        const [job, progress, targets] = await Promise.all([
            getTaskBaseRow(pool, jobId),
            getTaskProgressSummary(pool, jobId),
            getTaskTargets(pool, jobId)
        ]);

        if (!job) return res.status(404).json({ success: false, message: "Task not found" });

        const progressDetails = await getTaskProgressDetails(pool, jobId, -1, targets);
        return res.json({
            success: true,
            data: {
                task: normalizeTaskRow(job, progress),
                progress,
                targets,
                progressDetails
            }
        });
    } catch (err) {
        console.error("Failed to retrieve task detail:", err);
        return res.status(500).json({ success: false, message: "Failed to retrieve task detail", error: err.message || String(err) });
    }
}

async function sendTaskActionResponse(req, res) {
    let transaction;

    try {
        const jobId = getTaskIdFromRequest(req);
        const action = normalizeTaskValue(firstTaskDefined(req.body?.action, req.body?.Action, req.query?.action)).toLowerCase();

        if (!jobId) return res.status(400).json({ success: false, message: "job_id is required" });
        if (!["stop", "cancel", "delete"].includes(action)) {
            return res.status(400).json({ success: false, message: "Unsupported task action. Use stop, cancel, or delete." });
        }

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);

        if (action === "stop" || action === "cancel") {
            const newStatus = action === "stop" ? 2203 : 2204;
            const result = await pool.request()
                .input("Job_Idn", sql.Int, jobId)
                .input("Job_Status", sql.Int, newStatus)
                .query(`
                    SET NOCOUNT ON;

                    DECLARE @affectedJobRows int = 0;
                    DECLARE @affectedHistoryRows int = 0;

                    UPDATE TS_JOB
                    SET Job_Status = @Job_Status
                    WHERE Job_Idn = @Job_Idn;

                    SET @affectedJobRows = @@ROWCOUNT;

                    IF OBJECT_ID(N'TS_JOB_HISTORY', N'U') IS NOT NULL
                    BEGIN
                        UPDATE TS_JOB_HISTORY
                        SET Job_Status = @Job_Status,
                            LastChangedTime = GETDATE()
                        WHERE Job_Idn = @Job_Idn;

                        SET @affectedHistoryRows = @@ROWCOUNT;
                    END

                    SELECT
                        @affectedJobRows AS affectedRows,
                        @affectedHistoryRows AS affectedHistoryRows;
                `);

            const affectedRows = result.recordset?.[0]?.affectedRows || 0;
            const affectedHistoryRows = result.recordset?.[0]?.affectedHistoryRows || 0;
            return res.json({
                success: affectedRows > 0,
                message: affectedRows > 0 ? `Task ${action} updated.` : "Task not found.",
                data: {
                    Job_Idn: jobId,
                    Job_Status: newStatus,
                    statusLabel: resolveTaskStatusLabel(newStatus),
                    affectedRows,
                    affectedHistoryRows
                }
            });
        }

        transaction = new sql.Transaction(pool);
        await transaction.begin();

        const deleteConsoleIdn = parseTaskInt(firstTaskDefined(
            req.user?.console_Idn,
            req.user?.Console_Idn,
            req.body?.DeleteConsole_Idn,
            req.body?.deleteConsoleIdn
        ), 0);

        const deleteRequest = new sql.Request(transaction);
        const deleteResult = await deleteRequest
            .input("Job_Idn", sql.Int, jobId)
            .input("DeleteConsole_Idn", sql.Int, deleteConsoleIdn)
            .query(`
                DECLARE @archivedJob int = 0;
                DECLARE @archivedDest int = 0;
                DECLARE @deletedDest int = 0;
                DECLARE @deletedPkgJob int = 0;
                DECLARE @deletedHistory int = 0;
                DECLARE @deletedJob int = 0;

                IF NOT EXISTS (SELECT 1 FROM TS_JOB WHERE Job_Idn = @Job_Idn)
                BEGIN
                    SELECT
                        @archivedJob AS archivedJob,
                        @archivedDest AS archivedDest,
                        @deletedDest AS deletedDest,
                        @deletedPkgJob AS deletedPkgJob,
                        @deletedHistory AS deletedHistory,
                        @deletedJob AS deletedJob,
                        0 AS keptHistory;
                    RETURN;
                END

                IF OBJECT_ID(N'TS_JOB_DELHISTORY', N'U') IS NOT NULL
                BEGIN
                    INSERT INTO TS_JOB_DELHISTORY
                    (
                        Job_Idn,
                        Console_Idn,
                        Job_Type,
                        Job_Command,
                        Job_Style,
                        Job_Status,
                        Job_StartTime,
                        Job_EndTime,
                        Job_ScheduleTime,
                        Job_Dest_Type,
                        Job_Cmd_File,
                        Job_Opt_File,
                        Job_Speriod,
                        Job_Eperiod,
                        Job_Priority,
                        Job_Description,
                        DeleteConsole_Idn,
                        DeleteTime
                    )
                    SELECT
                        Job_Idn,
                        Console_Idn,
                        Job_Type,
                        Job_Command,
                        Job_Style,
                        Job_Status,
                        Job_StartTime,
                        Job_EndTime,
                        Job_ScheduleTime,
                        Job_Dest_Type,
                        Job_Cmd_File,
                        Job_Opt_File,
                        Job_Speriod,
                        Job_Eperiod,
                        Job_Priority,
                        Job_Description,
                        @DeleteConsole_Idn,
                        GETDATE()
                    FROM TS_JOB j
                    WHERE j.Job_Idn = @Job_Idn
                      AND NOT EXISTS (
                            SELECT 1
                            FROM TS_JOB_DELHISTORY dh
                            WHERE dh.Job_Idn = j.Job_Idn
                        );

                    SET @archivedJob = @@ROWCOUNT;
                END

                IF OBJECT_ID(N'TS_JOB_DEST_DELHISTORY', N'U') IS NOT NULL
                   AND OBJECT_ID(N'TS_JOB_DEST', N'U') IS NOT NULL
                BEGIN
                    INSERT INTO TS_JOB_DEST_DELHISTORY
                    (
                        Job_Idn,
                        Object_Root_Idn,
                        Object_Rel_Idn,
                        Object_Server_Idn,
                        Subnet_ID,
                        Flag,
                        Dest_Option1,
                        Dest_Option2,
                        Dest_Option3
                    )
                    SELECT
                        d.Job_Idn,
                        d.Object_Root_Idn,
                        d.Object_Rel_Idn,
                        d.Object_Server_Idn,
                        d.Subnet_ID,
                        d.Flag,
                        d.Dest_Option1,
                        d.Dest_Option2,
                        d.Dest_Option3
                    FROM TS_JOB_DEST d
                    WHERE d.Job_Idn = @Job_Idn
                      AND NOT EXISTS (
                            SELECT 1
                            FROM TS_JOB_DEST_DELHISTORY ddh
                            WHERE ddh.Job_Idn = d.Job_Idn
                              AND ISNULL(ddh.Object_Root_Idn, -1) = ISNULL(d.Object_Root_Idn, -1)
                              AND ISNULL(ddh.Object_Rel_Idn, -1) = ISNULL(d.Object_Rel_Idn, -1)
                              AND ISNULL(ddh.Object_Server_Idn, -1) = ISNULL(d.Object_Server_Idn, -1)
                              AND ISNULL(ddh.Subnet_ID, -1) = ISNULL(d.Subnet_ID, -1)
                        );

                    SET @archivedDest = @@ROWCOUNT;
                END

                IF OBJECT_ID(N'TS_JOB_DEST', N'U') IS NOT NULL
                BEGIN
                    DELETE FROM TS_JOB_DEST WHERE Job_Idn = @Job_Idn;
                    SET @deletedDest = @@ROWCOUNT;
                END

                IF OBJECT_ID(N'TS_PKGJOB', N'U') IS NOT NULL
                BEGIN
                    DELETE FROM TS_PKGJOB WHERE Job_Idn = @Job_Idn;
                    SET @deletedPkgJob = @@ROWCOUNT;
                END

                IF OBJECT_ID(N'TS_JOB_HISTORY', N'U') IS NOT NULL
                BEGIN
                    DELETE FROM TS_JOB_HISTORY WHERE Job_Idn = @Job_Idn;
                    SET @deletedHistory = @@ROWCOUNT;
                END

                DELETE FROM TS_JOB WHERE Job_Idn = @Job_Idn;
                SET @deletedJob = @@ROWCOUNT;

                SELECT
                    @archivedJob AS archivedJob,
                    @archivedDest AS archivedDest,
                    @deletedDest AS deletedDest,
                    @deletedPkgJob AS deletedPkgJob,
                    @deletedHistory AS deletedHistory,
                    @deletedJob AS deletedJob,
                    0 AS keptHistory;
            `);

        await transaction.commit();
        transaction = null;

        const data = deleteResult.recordset?.[0] || {};
        return res.json({
            success: Number(data.deletedJob || 0) > 0,
            message: Number(data.deletedJob || 0) > 0 ? "Task deleted." : "Task not found.",
            data: { Job_Idn: jobId, ...data }
        });
    } catch (err) {
        if (transaction) {
            try { await transaction.rollback(); } catch (rollbackErr) { console.error("Task delete rollback failed:", rollbackErr); }
        }

        console.error("Failed to perform task action:", err);
        return res.status(500).json({ success: false, message: "Failed to perform task action", error: err.message || String(err) });
    }
}

function sendTaskOptionsResponse(req, res) {
    return res.json({
        success: true,
        data: {
            classifications: [{ code: -1, label: "All" }, ...Object.entries(TASK_JOB_TYPE_LABELS).filter(([code]) => Number(code) !== 10310).map(([code, label]) => ({ code: Number(code), label }))],
            states: [{ code: -1, label: "All" }, ...Object.entries(TASK_JOB_STATUS_LABELS).map(([code, label]) => ({ code: Number(code), label }))],
            styles: Object.entries(TASK_JOB_STYLE_LABELS).map(([code, label]) => ({ code: Number(code), label })),
            commands: Object.entries(TASK_JOB_COMMAND_LABELS).map(([code, label]) => ({ code: Number(code), label }))
        }
    });
}

