function erResolveReport(reportId) {
  const rawId = erText(reportId, "executive-summary");
  const direct = erReportById.get(rawId);
  if (direct) return direct;

  const alias = EMA_FEATURED_REPORT_ALIASES[rawId];
  if (!alias) return erReportById.get("executive-summary");

  const target = alias.targetId ? erReportById.get(alias.targetId) : null;
  return {
    ...(target || {}),
    id: rawId,
    title: alias.title || target?.title || rawId,
    description: alias.description || target?.description || "Report generated from EMA operational data.",
    type: alias.type || target?.type || "Summary",
    source: alias.source || target?.source || "EMA Report Data",
    outputs: alias.outputs || target?.outputs || ["PDF"],
    category: alias.category || target?.category || "Featured Reports",
    categoryDesc: alias.categoryDesc || target?.categoryDesc || "Curated management-ready report packs.",
    icon: alias.icon || target?.icon || "chart",
    sourceReportId: alias.targetId || null
  };
}

function erText(value, fallback = "") {
  if (value === undefined || value === null) return fallback;
  const text = String(value).trim();
  return text || fallback;
}

function erNumber(value, fallback = 0) {
  const number = Number(value);
  return Number.isFinite(number) ? number : fallback;
}

function erPct(value, total) {
  if (!total) return 0;
  return Math.round((Number(value || 0) / Number(total || 0)) * 100);
}

function erSqlDate(value, fallback) {
  if (!value) return fallback;
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? fallback : date;
}

function erResolveDateRange(filters = {}) {
  const now = new Date();
  const end = erSqlDate(filters.endDate, now);
  const start = new Date(end);
  const range = erText(filters.dateRange, "current-month").toLowerCase();

  if (filters.startDate) return { startDate: erSqlDate(filters.startDate, start), endDate: end };

  if (range.includes("7")) start.setDate(end.getDate() - 7);
  else if (range.includes("30")) start.setDate(end.getDate() - 30);
  else if (range.includes("quarter")) {
    const month = end.getMonth();
    const quarterStartMonth = month - (month % 3);
    start.setMonth(quarterStartMonth, 1);
    start.setHours(0, 0, 0, 0);
  } else {
    start.setDate(1);
    start.setHours(0, 0, 0, 0);
  }

  return { startDate: start, endDate: end };
}

async function erTableExists(pool, tableName) {
  const result = await pool.request()
    .input("tableName", sql.NVarChar(128), tableName)
    .query(`SELECT 1 AS existsFlag FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = @tableName;`);
  return result.recordset.length > 0;
}

async function erColumnExists(pool, tableName, columnName) {
  const result = await pool.request()
    .input("tableName", sql.NVarChar(128), tableName)
    .input("columnName", sql.NVarChar(128), columnName)
    .query(`
      SELECT 1 AS existsFlag
      FROM INFORMATION_SCHEMA.COLUMNS
      WHERE TABLE_NAME = @tableName AND COLUMN_NAME = @columnName;
    `);
  return result.recordset.length > 0;
}

async function erFirstAvailableColumnExpr(pool, tableName, alias, candidates = [], fallbackExpr = "CAST('' AS NVARCHAR(255))") {
  for (const columnName of candidates) {
    if (await erColumnExists(pool, tableName, columnName)) {
      return `CAST(${alias}.[${columnName}] AS NVARCHAR(255))`;
    }
  }
  return fallbackExpr;
}

