const AP_DEVICE_CATEGORY_CASE_SQL = `
    CASE
        WHEN LOWER(ISNULL(RawMachineType, '')) LIKE '%laptop%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%notebook%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%latitude%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%inspiron%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%precision 3%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%precision 5%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%precision 7%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%xps%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%thinkpad%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%elitebook%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%probook%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%surface%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%macbook%'
          OR LOWER(ISNULL(Model, '')) LIKE '%laptop%'
          OR LOWER(ISNULL(Model, '')) LIKE '%notebook%'
          OR LOWER(ISNULL(Model, '')) LIKE '%latitude%'
          OR LOWER(ISNULL(Model, '')) LIKE '%inspiron%'
          OR LOWER(ISNULL(Model, '')) LIKE '%precision 3%'
          OR LOWER(ISNULL(Model, '')) LIKE '%precision 5%'
          OR LOWER(ISNULL(Model, '')) LIKE '%precision 7%'
          OR LOWER(ISNULL(Model, '')) LIKE '%xps%'
          OR LOWER(ISNULL(Model, '')) LIKE '%thinkpad%'
          OR LOWER(ISNULL(Model, '')) LIKE '%elitebook%'
          OR LOWER(ISNULL(Model, '')) LIKE '%probook%'
          OR LOWER(ISNULL(Model, '')) LIKE '%surface%'
          OR LOWER(ISNULL(Model, '')) LIKE '%macbook%'
            THEN 'Laptop'

        WHEN LOWER(ISNULL(RawMachineType, '')) LIKE '%desktop%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%optiplex%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%thinkcentre%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%elitedesk%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%prodesk%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%tower%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%asuspro%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%aio%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%all-in-one%'
          OR LOWER(ISNULL(RawMachineType, '')) IN ('pc', 'desktop')
          OR LOWER(ISNULL(Model, '')) LIKE '%desktop%'
          OR LOWER(ISNULL(Model, '')) LIKE '%optiplex%'
          OR LOWER(ISNULL(Model, '')) LIKE '%thinkcentre%'
          OR LOWER(ISNULL(Model, '')) LIKE '%elitedesk%'
          OR LOWER(ISNULL(Model, '')) LIKE '%prodesk%'
          OR LOWER(ISNULL(Model, '')) LIKE '%tower%'
          OR LOWER(ISNULL(Model, '')) LIKE '%asuspro%'
          OR LOWER(ISNULL(Model, '')) LIKE '%aio%'
          OR LOWER(ISNULL(Model, '')) LIKE '%all-in-one%'
            THEN 'Desktop'

        WHEN LOWER(ISNULL(RawMachineType, '')) LIKE '%server%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%vmware%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%poweredge%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%proliant%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%thinksystem%'
          OR LOWER(ISNULL(Model, '')) LIKE '%server%'
          OR LOWER(ISNULL(Model, '')) LIKE '%vmware%'
          OR LOWER(ISNULL(Model, '')) LIKE '%poweredge%'
          OR LOWER(ISNULL(Model, '')) LIKE '%proliant%'
          OR LOWER(ISNULL(Model, '')) LIKE '%thinksystem%'
            THEN 'Server'

        WHEN LOWER(ISNULL(RawMachineType, '')) LIKE '%android%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%ios%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%ipad%'
          OR LOWER(ISNULL(RawMachineType, '')) LIKE '%iphone%'
            THEN 'Mobile Device'

        ELSE 'Others'
    END
`;

function apText(value, fallback = "") {
    if (value === undefined || value === null) return fallback;
    return String(value).trim();
}

function apNumber(value, fallback = 0) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : fallback;
}

function apBool(value, fallback = false) {
    if (value === undefined || value === null || value === "") return fallback;
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value === 1;
    const text = String(value).trim().toLowerCase();
    return ["1", "true", "yes", "y", "on"].includes(text);
}

function apNormalizePricingRow(row = {}) {
    return {
        PricingID: row.PricingID,
        Category: apText(row.Category, "Others"),
        Brand: apText(row.Brand),
        Model: apText(row.Model),
        Price: apNumber(row.Price, 0),
        IsExcluded: apBool(row.IsExcluded, false),
        CreatedAt: row.CreatedAt || null,
        UpdatedAt: row.UpdatedAt || null
    };
}

function apReadPricingPayload(body = {}) {
    return {
        PricingID: Number(body.PricingID || body.pricingID || body.id || 0),
        Category: apText(body.Category ?? body.category, "Others") || "Others",
        Brand: apText(body.Brand ?? body.brand),
        Model: apText(body.Model ?? body.model),
        Price: apNumber(body.Price ?? body.price, 0),
        IsExcluded: apBool(body.IsExcluded ?? body.isExcluded, false)
    };
}

function apUnifiedDeviceBaseSql() {
    return `
        SELECT
            LTRIM(RTRIM(ISNULL(a.MadeCompany, ''))) AS Brand,
            LTRIM(RTRIM(ISNULL(a.Model, ''))) AS Model,
            LTRIM(RTRIM(ISNULL(ci.MachineType, ''))) AS RawMachineType
        FROM TS_OBJECT_ROOT a WITH (NOLOCK)
        LEFT JOIN TS_CLIENT_INFO ci WITH (NOLOCK)
            ON a.Object_Root_Idn = ci.Object_Root_Idn

        UNION ALL

        SELECT
            LTRIM(RTRIM(ISNULL(a.DeviceManufacture, ''))) AS Brand,
            LTRIM(RTRIM(ISNULL(COALESCE(NULLIF(a.DeviceModelName, ''), NULLIF(a.ModelNumber, '')), ''))) AS Model,
            LTRIM(RTRIM(ISNULL(a.PlatformType, ''))) AS RawMachineType
        FROM TSMDM_ASSET a WITH (NOLOCK)
    `;
}

