app.get("/api/settings/device-pricing/brands", authenticateToken, async (req, res) => {
    try {
        const category = apText(req.query.category);
        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);

        const result = await pool.request()
            .input("Category", sql.NVarChar(100), category)
            .query(`
                WITH DeviceBase AS (
                    ${apUnifiedDeviceBaseSql()}
                ),
                DeviceCategoryResult AS (
                    SELECT
                        Brand,
                        ${AP_DEVICE_CATEGORY_CASE_SQL} AS DeviceCategory
                    FROM DeviceBase
                )
                SELECT DISTINCT Brand
                FROM DeviceCategoryResult
                WHERE Brand IS NOT NULL
                  AND LTRIM(RTRIM(Brand)) <> ''
                  AND (@Category = '' OR DeviceCategory = @Category)
                ORDER BY Brand;
            `);

        return res.json((result.recordset || []).map((row) => row.Brand));
    } catch (err) {
        console.error("GET /api/settings/device-pricing/brands error:", err);
        return res.status(500).json({
            success: false,
            message: "Failed to fetch device pricing brands.",
            error: err.message
        });
    }
});

