async function apListPricingHandler(req, res) {
    try {
        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);

        const result = await pool.request().query(`
            SELECT
                PricingID,
                ISNULL(Category, 'Others') AS Category,
                ISNULL(Brand, '') AS Brand,
                ISNULL(Model, '') AS Model,
                ISNULL(Price, 0) AS Price,
                ISNULL(IsExcluded, 0) AS IsExcluded,
                CreatedAt,
                UpdatedAt
            FROM AssetPricing WITH (NOLOCK)
            ORDER BY Category, Brand, Model, PricingID;
        `);

        return res.json((result.recordset || []).map(apNormalizePricingRow));
    } catch (err) {
        console.error("GET device pricing error:", err);
        return res.status(500).json({
            success: false,
            message: "Failed to load device pricing.",
            error: err.message
        });
    }
}

