const PC_AGING_RULE_KEY = "PC_AGING_RULE";

const DEFAULT_PC_AGING_RULE = {
    enabled: true,
    ageSource: "RegDate",
    healthyMaxYears: 3,
    monitorMaxYears: 5,
    agingMinYears: 5,
    includeUnknownAge: false,
    replacementWindowMonths: 6,
    notes: "PC aging rule used for dashboard and replacement planning."
};

function parsePcAgingBool(value, fallback = false) {
    if (value === undefined || value === null || value === "") return fallback;
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value === 1;

    const text = String(value).trim().toLowerCase();
    return ["1", "true", "yes", "y", "on"].includes(text);
}

function parsePcAgingNumber(value, fallback = 0) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : fallback;
}

function normalizePcAgingRule(input = {}) {
    const allowedSources = new Set([
        "RegDate",
        "HIUpdateTime",
        "ConnectionTime"
    ]);

    const ageSource = allowedSources.has(String(input.ageSource || "").trim())
        ? String(input.ageSource).trim()
        : DEFAULT_PC_AGING_RULE.ageSource;

    const healthyMaxYears = parsePcAgingNumber(
        input.healthyMaxYears,
        DEFAULT_PC_AGING_RULE.healthyMaxYears
    );

    const monitorMaxYears = parsePcAgingNumber(
        input.monitorMaxYears,
        DEFAULT_PC_AGING_RULE.monitorMaxYears
    );

    const agingMinYears = parsePcAgingNumber(
        input.agingMinYears,
        DEFAULT_PC_AGING_RULE.agingMinYears
    );

    return {
        enabled: parsePcAgingBool(input.enabled, DEFAULT_PC_AGING_RULE.enabled),
        ageSource,
        healthyMaxYears,
        monitorMaxYears,
        agingMinYears,
        includeUnknownAge: parsePcAgingBool(
            input.includeUnknownAge,
            DEFAULT_PC_AGING_RULE.includeUnknownAge
        ),
        replacementWindowMonths: parsePcAgingNumber(
            input.replacementWindowMonths,
            DEFAULT_PC_AGING_RULE.replacementWindowMonths
        ),
        notes: String(input.notes ?? DEFAULT_PC_AGING_RULE.notes).trim()
    };
}

function safeParsePcAgingJson(value) {
    if (!value) return DEFAULT_PC_AGING_RULE;

    try {
        const parsed = JSON.parse(String(value));
        return normalizePcAgingRule({
            ...DEFAULT_PC_AGING_RULE,
            ...parsed
        });
    } catch (err) {
        return DEFAULT_PC_AGING_RULE;
    }
}

