        //             ISNULL(SUM(f.Pkg_File_ZSize), 0) AS SizeAfterCompression,
        //             MAX(ISNULL(i.Exclude, 0)) AS Exclude,
        //             MAX(ISNULL(f.Pkg_File_Execute, 0)) AS RemoteExecuteFile,
        //             v.AllVersions
