// Count pop-up/details behind Registered / Not Registered / Not Installed / Other Device.
// For agent status details: spGetSubnetNIAgentDetail2
// For object/device details: spGetSubnetNIObjectDetail3
app.get("/api/network/subnet/:subnet/details", authenticateToken, async (req, res) => {
    try {
        const subnet = normalizeNetworkValue(req.params.subnet);
        const detailType = normalizeNetworkValue(req.query.type || "registered");
        const destDate = normalizeDateForNetwork(req.query.destDate);
        const systemType = parseNetworkInt(req.query.systemType, 0);
        const tca = parseNetworkInt(req.query.tca, 0);

        if (!subnet) {
            return res.status(400).json({ success: false, message: "subnet is required" });
        }

        const codeMap = {
            registered: 1,
            notregistered: 2,
            notinstalled: 3,
            otherdevice: 4,
            other: 4
        };
        const normalizedType = detailType.replace(/[\s_-]+/g, "").toLowerCase();
        const code = parseNetworkInt(req.query.ncode || req.query.code, codeMap[normalizedType] || 1);

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        const procedure = normalizedType === "registered" || normalizedType === "notregistered"
            ? "spGetSubnetNIAgentDetail2"
            : "spGetSubnetNIObjectDetail3";

        const data = await executeNetworkProcedure(pool, procedure, procedure === "spGetSubnetNIAgentDetail2"
            ? {
                Subnet: { type: sql.VarChar(50), value: subnet },
                nCode: { type: sql.Int, value: code }
            }
            : {
                Subnet: { type: sql.VarChar(50), value: subnet },
                nSystemType: { type: sql.Int, value: systemType || code },
                tmpDestDate: { type: sql.VarChar(50), value: destDate || await getNetworkLastSearchDate(pool) },
                bTCA: { type: sql.Int, value: tca }
            }
        );

        const normalizedData = data.map((row, index) => normalizeDeviceStatusDetail(row, index, detailType));
        const paged = paginateRows(normalizedData, req);

        return res.json({
            success: true,
            subnet,
            type: detailType,
            procedure,
            ...paged
        });
    } catch (err) {
        console.error(err);
        return res.status(500).json({ success: false, message: "Failed to retrieve subnet details" });
    }
});

