app.post("/api/restrictions/app/package-manager", authenticateToken, async (req, res) => {
    const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
    const transaction = new sql.Transaction(pool);

    try {
        const payload = normalizePackageManagerPayload(req.body || {});
        if (!payload.SW_Pkg_Name) return res.status(400).json({ success: false, message: "Package name is required." });

        await transaction.begin();
        const tableInfo = await getPackageManagerTableInfo(transaction);
        const packageGuid = normalizeRestrictionValue(req.body?.SW_Pkg_Guid || req.body?.packageGuid || crypto.randomUUID()).toUpperCase();
        const etcInfo = payload.SW_Package_EtcInfo || normalizePackageFilePayload(payload.files?.[0] || {}).FileName || "";

        let packageId = 0;
        const insertRequest = new sql.Request(transaction)
            .input("SW_Pkg_Name", sql.VarChar(255), payload.SW_Pkg_Name)
            .input("SW_Pkg_Company", sql.VarChar(255), payload.SW_Pkg_Company)
            .input("License_Qnt", sql.Int, payload.License_Qnt)
            .input("Use_Statistices", sql.Int, payload.Use_Statistices)
            .input("Cur_Count", sql.Int, payload.Cur_Count)
            .input("SW_Package_EtcInfo", sql.VarChar(sql.MAX), etcInfo)
            .input("SW_Catg", sql.Int, payload.SW_Catg)
            .input("SW_Pkg_Guid", sql.VarChar(50), packageGuid)
            .input("Selected", sql.Int, payload.Selected);

        if (tableInfo.packageHasIdentity) {
            const inserted = await insertRequest.query(`
                INSERT INTO TSSI_PACKAGE
                (
                    SW_Pkg_Name, SW_Pkg_Company, License_Qnt, Use_Statistices,
                    Cur_Count, SW_Package_EtcInfo, SW_Catg, SW_Pkg_Guid, Selected
                )
                OUTPUT inserted.SW_Pkg_Idn
                VALUES
                (
                    @SW_Pkg_Name, @SW_Pkg_Company, @License_Qnt, @Use_Statistices,
                    @Cur_Count, @SW_Package_EtcInfo, @SW_Catg, @SW_Pkg_Guid, @Selected
                );
            `);
            packageId = parseRestrictionInt(inserted.recordset?.[0]?.SW_Pkg_Idn, 0);
        } else {
            packageId = await getNextPackageId(transaction);
            insertRequest.input("SW_Pkg_Idn", sql.Int, packageId);
            await insertRequest.query(`
                INSERT INTO TSSI_PACKAGE
                (
                    SW_Pkg_Idn, SW_Pkg_Name, SW_Pkg_Company, License_Qnt, Use_Statistices,
                    Cur_Count, SW_Package_EtcInfo, SW_Catg, SW_Pkg_Guid, Selected
                )
                VALUES
                (
                    @SW_Pkg_Idn, @SW_Pkg_Name, @SW_Pkg_Company, @License_Qnt, @Use_Statistices,
                    @Cur_Count, @SW_Package_EtcInfo, @SW_Catg, @SW_Pkg_Guid, @Selected
                );
            `);
        }

        for (const file of payload.files) {
            const normalizedFile = normalizePackageFilePayload(file);
            if (!normalizedFile.FileName) continue;
            await insertPackageFile(transaction, packageId, packageGuid, normalizedFile);
        }

        await transaction.commit();
        const data = await getPackageManagerDetail(pool, packageId);
        return res.status(201).json({ success: true, message: "Package created.", data });
    } catch (err) {
        try { await transaction.rollback(); } catch (_) {}
        console.error("Failed to create package:", err);
        return res.status(500).json({ success: false, message: "Failed to create package", error: err.message || String(err) });
    }
});

