app.delete("/api/restrictions/app/package-manager/:packageId", authenticateToken, async (req, res) => {
    const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
    const transaction = new sql.Transaction(pool);

    try {
        const packageId = parseRestrictionInt(req.params.packageId, 0);
        if (!packageId) return res.status(400).json({ success: false, message: "Invalid package ID." });

        const usage = await pool.request()
            .input("SW_Pkg_Idn", sql.Int, packageId)
            .query("SELECT COUNT(1) AS usedCount FROM TSSWB_PKG WHERE SW_Pkg_Idn = @SW_Pkg_Idn;");

        const usedCount = parseRestrictionInt(usage.recordset?.[0]?.usedCount, 0);
        if (usedCount > 0) {
            return res.status(409).json({
                success: false,
                message: "This package is already used by one or more restriction policies and cannot be deleted.",
                used_policy_count: usedCount
            });
        }

        await transaction.begin();
        await new sql.Request(transaction)
            .input("SW_Pkg_Idn", sql.Int, packageId)
            .query("DELETE FROM TSSI_PACKAGE_FILES WHERE SW_Pkg_Idn = @SW_Pkg_Idn; DELETE FROM TSSI_PACKAGE WHERE SW_Pkg_Idn = @SW_Pkg_Idn;");
        await transaction.commit();

        return res.json({ success: true, message: "Package deleted.", data: null });
    } catch (err) {
        try { await transaction.rollback(); } catch (_) {}
        console.error("Failed to delete package:", err);
        return res.status(500).json({ success: false, message: "Failed to delete package", error: err.message || String(err) });
    }
});

