app.post("/api/restrictions/whitelist/default-permitted", authenticateToken, async (req, res) => {
    let transaction;

    try {
        const selected = restrictionArray(firstRestrictionDefined(
            req.body?.software_ids,
            req.body?.softwareIds,
            req.body?.selected_ids,
            req.body?.selectedIds,
            req.body?.items,
            req.body?.data,
            req.body?.package_list
        ));

        const pool = await getDbPool(typeof req !== 'undefined' ? req : null);
        const tableInfo = await getWhitelistTableInfo(pool);
        if (!tableInfo.hasPermitTable || !tableInfo.permitHasIsBase) {
            return res.status(501).json({ success: false, message: "TSSWB_WL_SW_PERMIT table or IsBase column is not available in this database." });
        }

        transaction = new sql.Transaction(pool);
        await transaction.begin();

        await new sql.Request(transaction).query("DELETE FROM TSSWB_WL_SW_PERMIT WHERE ISNULL(IsBase, 0) = 1;");

        for (const item of selected) {
            const wlSwIdn = parseWhitelistSoftwareId(typeof item === "object" ? firstRestrictionDefined(item.WLSWIdn, item.id, item.SW_Pkg_Idn, item.sourcePackageId) : item, 0);
            if (!wlSwIdn) continue;

            await ensureWhitelistSoftwareExists(transaction, typeof item === "object" ? item : { WLSWIdn: wlSwIdn });

            await new sql.Request(transaction)
                .input("WLSWIdn", sql.Int, wlSwIdn)
                .input("IsBase", sql.Int, 1)
                .query(`
                    DECLARE @Sql nvarchar(max);

                    IF COL_LENGTH('TSSWB_WL_SW_PERMIT', 'policy_id') IS NULL
                    BEGIN
                        SET @Sql = N'INSERT INTO TSSWB_WL_SW_PERMIT (WLSWIdn, IsBase) VALUES (@WLSWIdn, @IsBase);';
                    END
                    ELSE
                    BEGIN
                        SET @Sql = N'INSERT INTO TSSWB_WL_SW_PERMIT (policy_id, WLSWIdn, IsBase) VALUES (0, @WLSWIdn, @IsBase);';
                    END

                    EXEC sp_executesql
                        @Sql,
                        N'@WLSWIdn int, @IsBase int',
                        @WLSWIdn = @WLSWIdn,
                        @IsBase = @IsBase;
                `);
        }

        await transaction.commit();
        transaction = null;

        return res.json({ success: true, message: "Default permitted software saved.", data: { count: selected.length } });
    } catch (err) {
        if (transaction) {
            try { await transaction.rollback(); } catch (rollbackErr) { console.error("Default permitted rollback failed:", rollbackErr); }
        }
        console.error("Failed to save default permitted software:", err);
        return res.status(500).json({ success: false, message: "Failed to save default permitted software", error: err.message || String(err) });
    }
});

